# Ray worker nodes on some clusters inherit stale REQUESTS_CA_BUNDLE / SSL_CERT_FILE
# values.  When those paths do not exist, requests fails before it ever reaches the
# URL.  Clean invalid CA env vars at import time on both the head node and every
# Ray worker, then prefer certifi when available.
def _configure_requests_ca_environment():
    invalid_envs = []
    for env_name in ("REQUESTS_CA_BUNDLE", "CURL_CA_BUNDLE", "SSL_CERT_FILE"):
        env_value = os.environ.get(env_name)
        if env_value and not os.path.exists(env_value):
            invalid_envs.append((env_name, env_value))
            os.environ.pop(env_name, None)

    ca_path = None
    try:
        import certifi  # noqa: F401
        ca_path = certifi.where()
    except Exception:
        ca_path = None

    if ca_path and os.path.exists(ca_path):
        os.environ["REQUESTS_CA_BUNDLE"] = ca_path
        os.environ["SSL_CERT_FILE"] = ca_path

    return ca_path, invalid_envs

REQUESTS_CA_BUNDLE_PATH, INVALID_CA_ENV_VARS = _configure_requests_ca_environment()
REQUESTS_VERIFY = REQUESTS_CA_BUNDLE_PATH if REQUESTS_CA_BUNDLE_PATH else True

