class ClippedRegressionProbabilityWrapper:
    """
    Wrap a fitted regressor so old viewer/realtime code that expects predict_proba still works.

    The model is trained as a regression task on a 0-1 fractional coverage target.  The wrapper
    clips predictions to [0, 1] and exposes predict_proba(X)[:, 1] as the clipped forecast.
    """
    def __init__(self, base_model):
        self.base_model = base_model

    def predict(self, X):
        p = self.base_model.predict(X)
        return np.clip(np.asarray(p, dtype=np.float32), 0.0, 1.0)

    def predict_proba(self, X):
        p = self.predict(X)
        return np.column_stack([1.0 - p, p]).astype(np.float32)

    @property
    def feature_importances_(self):
        return getattr(self.base_model, "feature_importances_")

    def get_booster(self):
        return self.base_model.get_booster()


