#     https://mtarchive.geol.iastate.edu/YYYY/MM/DD/mrms/ncep/<product>/<product>_00.00_YYYYMMDD-HH0000.grib2.gz
#
# Product transition used here:
#   - 2019 and earlier historical cases generally use GaugeCorr_QPE_01H.
#   - 2021+ cases generally use MultiSensor_QPE_01H_Pass2.
# The resolver still tries both archived products for robustness. NCEP realtime is kept only as a final fallback
# for realtime use after training, not as the primary training archive.
MRMS_PRIMARY_PRODUCT = "MultiSensor_QPE_01H_Pass2"
MRMS_LEGACY_PRODUCT = "GaugeCorr_QPE_01H"
MRMS_IEM_MTARCHIVE_BASE = "https://mtarchive.geol.iastate.edu"
# NCSU/NCEI THREDDS archive fills the big historical gap before IEM/MTArchive
# raw MRMS GRIB coverage becomes consistent.  It uses leading "MRMS_" filenames
# and uncompressed GRIB2 files under /thredds/fileServer/ncei/mrms/YYYYMM/YYYYMMDD/.
MRMS_NCSU_THREDDS_BASE = "https://thredds.climate.ncsu.edu/thredds/fileServer/ncei/mrms"
MRMS_USE_NCSU_THREDDS_ARCHIVE = True
MRMS_ALLOW_REALTIME_NCEP_FALLBACK = os.environ.get("HAZARD_ML_MRMS_REALTIME_FALLBACK", "0").strip().lower() in {"1", "true", "yes", "y"}

# Guardrail: do not silently train on a badly incomplete date set.
# v24d had only ~134/242 chunks because archived MRMS fallback was incomplete.
