HYDRO_TARGET_PREFIXES = (
    "Obs_MRMS_FFG_",
    "Obs_MRMS_",
    "Obs_FFG_",
    "Obs_QPE_to_FFG_",
    "LSR_",
)

# Backward-compatible alias used by the prior-chunk reuse path.  Keep this
# at module scope so local multiprocessing/Ray workers see it immediately.
OBSERVED_LEAKAGE_PREFIXES = HYDRO_TARGET_PREFIXES


def validate_required_module_globals():
    """Fail fast before any expensive extraction if patch-critical globals are missing."""
    required_names = [
        "TARGET_COLUMN",
        "HYDRO_TARGET_PREFIXES",
        "OBSERVED_LEAKAGE_PREFIXES",
        "PRIOR_RAP_FEATURE_CHUNK_DIRS",
    ]
    missing = [name for name in required_names if name not in globals()]
    if missing:
        raise RuntimeError(f"Internal script error: missing required globals: {missing}")



def validate_single_training_target_configuration(feature_columns=None):
    """Guardrail: exactly one dataframe column may be treated as the fitted model target."""
    allowed_target = str(TRAIN_TARGET_COLUMN)
    if not allowed_target.startswith("Target_"):
        raise RuntimeError(f"TRAIN_TARGET_COLUMN must be the only Target_* model target column, got {allowed_target!r}")
    if feature_columns is not None:
        bad = [str(c) for c in feature_columns if str(c).startswith("Target_")]
        if bad:
            raise RuntimeError(
                "Target-like columns leaked into model predictors. "
                f"The only fitted target is {allowed_target!r}; leaked predictors: {bad[:50]}"
            )
    return True


def validate_single_target_dataframe_columns(frame, label="frame"):
    """Fail if any old/alternate Target_* columns are present in the modeling dataframe."""
    if frame is None or not hasattr(frame, "columns"):
        return True
    target_like = [str(c) for c in frame.columns if str(c).startswith("Target_")]
    unexpected = sorted(c for c in target_like if c != str(TRAIN_TARGET_COLUMN))
    if unexpected:
        raise RuntimeError(
            f"{label} contains alternate Target_* columns: {unexpected[:50]}. "
            f"This run is single-target only; delete/rebuild old v28/r75km caches so only {TRAIN_TARGET_COLUMN!r} remains."
        )
    if str(TRAIN_TARGET_COLUMN) not in target_like:
        raise RuntimeError(f"{label} is missing the only model target {TRAIN_TARGET_COLUMN!r}.")
    return True

def _target_duration_tag(duration_h):
    return f"{int(duration_h):02d}h"


def _ffg_duration_columns(duration_h):
    tag = _target_duration_tag(duration_h)
    return {
        "target": f"Obs_MRMS_FFG_{tag}_Exceeded",
        "max_qpe": f"Obs_MRMS_QPE_{tag}_Max_mm",
        "ffg_at_max": f"Obs_FFG_{tag}_AtMaxRatio_mm",
        "max_ratio": f"Obs_QPE_to_FFG_{tag}_MaxRatio",
        "valid_windows": f"Obs_FFG_{tag}_ValidWindows",
    }


def _latlon_to_unit_xyz_for_r75km(lat, lon):
    lat = np.deg2rad(np.asarray(lat, dtype=float))
    lon = np.deg2rad(np.asarray(lon, dtype=float))
    return np.column_stack([
        np.cos(lat) * np.cos(lon),
        np.cos(lat) * np.sin(lon),
        np.sin(lat),
    ])


def build_r75km_fractional_target_arrays(binary_target_1d, lats_1d, lons_1d, radius_km=R40KM_TARGET_RADIUS_KM, chunk_size=5000):
    """
    Build an ERO-like neighborhood fractional target on the native RAP-domain grid.

    For each RAP grid point, the target is the fraction of RAP grid points within radius_km
    that had the binary MRMS/FFG exceedance target. The center point is included.

    Returns:
      frac_target: float32 0-1
      neighbor_count: int16
      event_count: int16
    """
    y = np.asarray(binary_target_1d, dtype=np.float32).reshape(-1)
    lat = np.asarray(lats_1d, dtype=float).reshape(-1)
    lon = np.asarray(lons_1d, dtype=float).reshape(-1)

    if len(y) != len(lat) or len(y) != len(lon):
        raise ValueError(
            f"R75km target inputs have mismatched lengths: y={len(y)}, lat={len(lat)}, lon={len(lon)}"
        )

    ok = np.isfinite(lat) & np.isfinite(lon) & np.isfinite(y)
    frac = np.zeros(len(y), dtype=np.float32)
    neighbor_count = np.zeros(len(y), dtype=np.int16)
    event_count = np.zeros(len(y), dtype=np.int16)

    if not ok.any():
        return frac, neighbor_count, event_count

    ok_idx = np.where(ok)[0]
    xyz = _latlon_to_unit_xyz_for_r75km(lat[ok], lon[ok])
    y_ok = y[ok]
    tree = cKDTree(xyz)

    earth_radius_km = 6371.0
    angular_radius = float(radius_km) / earth_radius_km
    chord_radius = 2.0 * np.sin(angular_radius / 2.0)

    for start in range(0, len(ok_idx), int(chunk_size)):
        end = min(start + int(chunk_size), len(ok_idx))
        neighbor_lists = tree.query_ball_point(xyz[start:end], r=chord_radius)

        for local_i, neigh in enumerate(neighbor_lists):
            global_i = ok_idx[start + local_i]
            if not neigh:
                continue
            vals = y_ok[np.asarray(neigh, dtype=int)]
            n = int(len(vals))
            e = int(np.sum(vals))
            neighbor_count[global_i] = n
            event_count[global_i] = e
            frac[global_i] = np.float32(e / max(1, n))

    return np.clip(frac, 0.0, 1.0).astype(np.float32), neighbor_count, event_count


def _is_non_predictor_column(col):
    """
    Columns that must be kept for bookkeeping/verification but dropped before fitting.
    This is the leakage guard for v26: observed MRMS QPE/FFG and LSR data cannot enter X.
    """
    col = str(col)
    if col in {"Date", "Lat", "Lon", "Year", TARGET_COLUMN, TRAIN_TARGET_COLUMN, R40KM_FRACTION_COLUMN, R40KM_TARGET_COUNT_COLUMN, R40KM_TARGET_EVENT_COUNT_COLUMN}:
        return True
    if col == "Obs_LSR_FlashFlood_Report":
        return True
    if _is_deprecated_or_raw_period_predictor(col):
        return True
    return any(col.startswith(prefix) for prefix in HYDRO_TARGET_PREFIXES)


