_ARTIFACT_FALLBACK_WARNED = False


def _path_write_test(directory):
    """Return True if directory can be created and written to."""
    test_path = None
    try:
        os.makedirs(directory, exist_ok=True)
        test_path = os.path.join(directory, f".write_test_{os.getpid()}")
        with open(test_path, "w") as f:
            f.write("ok\n")
        with open(test_path, "r") as f:
            _ = f.read()
        return True
    except Exception:
        return False
    finally:
        if test_path:
            try:
                if os.path.exists(test_path):
                    os.remove(test_path)
            except Exception:
                pass


def project_mount_looks_live():
    """
    Best-effort check that /home/tyreekfrazier/ISU_Research is still the expected
    project/mtdesktop mount, not the exposed underlying local directory after sshfs drops.
    """
    sentinel_paths = [
        MODE_2018_CSV,
        MODE_2024_CSV,
        MODE_2025_CSV,
        PRIOR_RAP_FEATURE_CHUNK_DIRS[0] if PRIOR_RAP_FEATURE_CHUNK_DIRS else "",
    ]
    existing = [p for p in sentinel_paths if p and os.path.exists(p)]
    return len(existing) >= 2


def require_project_mount_live(stage):
    """
    Abort data/chunk writes if the project mount disappeared.  This prevents
    accidentally writing daily chunks/master parquets into the hidden local
    directory underneath an sshfs mount point.
    """
    if project_mount_looks_live():
        return True

    msg = (
        f"Project mount does not look live during: {stage}\n"
        f"Expected at least two sentinel paths to exist under {PROJECT_ROOT}, for example:\n"
        f"  {MODE_2018_CSV}\n"
        f"  {PRIOR_RAP_FEATURE_CHUNK_DIRS[0] if PRIOR_RAP_FEATURE_CHUNK_DIRS else '(no prior chunk dir configured)'}\n"
        "This usually means the mtdesktop/sshfs mount disconnected. Remount it before continuing."
    )
    raise RuntimeError(msg)


def get_artifact_cache_dir(for_write=True, context="artifact"):
    """
    Return the cache directory to use for model/scaler/result artifacts.

    For writes, prefer CACHE_DIR only when the project mount still looks live and
    CACHE_DIR is writable.  Otherwise write to LOCAL_ARTIFACT_FALLBACK_DIR, which
    is deliberately outside /home/tyreekfrazier/ISU_Research so it will not be
    hidden by remounting sshfs later.
    """
    global _ARTIFACT_FALLBACK_WARNED

    primary_ok = project_mount_looks_live() and _path_write_test(CACHE_DIR)
    if primary_ok:
        return CACHE_DIR

    fallback_ok = _path_write_test(LOCAL_ARTIFACT_FALLBACK_DIR)
    if not fallback_ok:
        raise RuntimeError(
            f"Primary artifact directory is not safe/writable: {CACHE_DIR}\n"
            f"Fallback artifact directory is also not writable: {LOCAL_ARTIFACT_FALLBACK_DIR}"
        )

    if not _ARTIFACT_FALLBACK_WARNED:
        print("\n" + "!" * 80)
        print("WARNING: project mount/CACHE_DIR is not available for artifact output.")
        print(f"Context: {context}")
        print(f"Primary CACHE_DIR: {CACHE_DIR}")
        print(f"Writing model/scaler/results artifacts to local fallback instead:")
        print(f"  {LOCAL_ARTIFACT_FALLBACK_DIR}")
        print("After remounting, copy these files back to the normal prob_flood_models directory.")
        print("!" * 80 + "\n")
        _ARTIFACT_FALLBACK_WARNED = True

    return LOCAL_ARTIFACT_FALLBACK_DIR


def cache_file_path(filename, for_write=False, context="artifact"):
    """
    Resolve an artifact path.  For reads, check primary then fallback. For writes,
    dynamically choose primary vs fallback based on current mount health.
    """
    if for_write:
        return os.path.join(get_artifact_cache_dir(for_write=True, context=context), filename)

    primary = os.path.join(CACHE_DIR, filename)
    if os.path.exists(primary):
        return primary

    fallback = os.path.join(LOCAL_ARTIFACT_FALLBACK_DIR, filename)
    if os.path.exists(fallback):
        return fallback

    return primary


def write_json_safely(obj, path):
    tmp = path + ".tmp"
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(tmp, "w") as f:
        json.dump(obj, f, indent=2)
    os.replace(tmp, path)


