def extract_unique_dates(csv_list):
    dfs = [pd.read_csv(f) for f in csv_list if os.path.exists(f)]

    if not dfs:
        raise FileNotFoundError(
            "No MODE CSV files were found. Check MODE_2018_CSV / MODE_2024_CSV / MODE_2025_CSV paths."
        )

    df_all = pd.concat(dfs, ignore_index=True)

    dates = []
    for _, row in df_all.iterrows():
        try:
            dates.append(f"{int(row['Year'])}{int(row['Month']):02d}{int(row['Day']):02d}")
        except Exception:
            continue

    return sorted(list(set(dates)))


def get_nam_domain_mask(sample_grib_file):
    grbs = pygrib.open(sample_grib_file)
    lats, lons = grbs.message(1).latlons()
    grbs.close()

    lons = np.where(lons > 180, lons - 360, lons)
    domain_mask = ((lats >= TRAIN_DOMAIN_LAT_MIN) & (lats <= TRAIN_DOMAIN_LAT_MAX) & (lons >= TRAIN_DOMAIN_LON_MIN) & (lons <= TRAIN_DOMAIN_LON_MAX))

    return lats, lons, domain_mask, lats[domain_mask], lons[domain_mask]


def filter_dataframe_to_training_domain(df):
    """Filter a prior/full-domain daily chunk to the active v26f training domain."""
    if df is None or df.empty or "Lat" not in df.columns or "Lon" not in df.columns:
        return df
    lat = pd.to_numeric(df["Lat"], errors="coerce")
    lon = pd.to_numeric(df["Lon"], errors="coerce")
    keep = (
        (lat >= float(TRAIN_DOMAIN_LAT_MIN))
        & (lat <= float(TRAIN_DOMAIN_LAT_MAX))
        & (lon >= float(TRAIN_DOMAIN_LON_MIN))
        & (lon <= float(TRAIN_DOMAIN_LON_MAX))
    )
    return df.loc[keep].copy()


def _safe_grib_key(grb, key, default=None):
    try:
        val = getattr(grb, key)
        if val is not None:
            return val
    except Exception:
        pass

    try:
        val = grb[key]
        if val is not None:
            return val
    except Exception:
        pass

    return default


def _extract_yyyymmdd_from_filename(filename):
    """
    Extract YYYYMMDD from a RAP filename. Returns None if not found.

    Expected new names look like:
      nam_12km_20240620_12z_f03.grib2

    This also safely ignores older files with names like nam_0hr... that do not
    contain a usable date in the expected split position.
    """
    base = os.path.basename(str(filename))
    match = re.search(r"(20\d{6}|19\d{6})", base)
    return match.group(1) if match else None


def _parse_grib_message_end_hour_for_validation(grb):
    """
    Best-effort forecast/accumulation end hour from a GRIB message.
    """
    for key in ["endStep", "forecastTime", "forecastTimeInHours"]:
        val = _safe_grib_key(grb, key, None)
        if val is not None:
            try:
                return int(float(str(val).split("-")[-1]))
            except Exception:
                pass

    step_range = _safe_grib_key(grb, "stepRange", None)
    if step_range is not None:
        txt = str(step_range)
        vals = re.findall(r"-?\d+", txt)
        if vals:
            try:
                return int(vals[-1])
            except Exception:
                pass

    return None


def validate_nam_forecast_file(path, date_str, expected_fhr, cycle_hour=RAP_INIT_CYCLE_HOUR, verbose=False):
    """
    Validate a local RAP GRIB2 file for the expected date/cycle/forecast hour.

    expected_fhr is the feature offset from 12z.
    actual_file_fhr = expected_fhr + RAP_FILE_FHR_OFFSET.
    """
    if not os.path.exists(path):
        return False

    try:
        size = os.path.getsize(path)
        if size < RAP_MIN_FILE_SIZE_BYTES:
            if verbose:
                tqdm.write(f"Invalid RAP file too small ({size} bytes): {path}")
            return False
    except Exception:
        return False

    try:
        expected_date = int(str(date_str))
    except Exception:
        if verbose:
            tqdm.write(f"Invalid RAP validation date string: {date_str!r} for file {path}")
        return False

    expected_time = int(cycle_hour * 100)
    expected_actual_fhr = int(expected_fhr) + RAP_FILE_FHR_OFFSET

    try:
        grbs = pygrib.open(path)
    except Exception as e:
        if verbose:
            tqdm.write(f"Invalid RAP file cannot open as GRIB2: {path} | {e}")
        return False

    saw_any_message = False
    saw_expected_date_time = False
    saw_wrong_date_time = False
    saw_expected_fhr = False
    saw_any_fhr_metadata = False

    try:
        for idx, grb in enumerate(grbs, start=1):
            if idx > 200:
                break

            saw_any_message = True

            data_date = _safe_grib_key(grb, "dataDate", None)
            data_time = _safe_grib_key(grb, "dataTime", None)

            try:
                data_date_i = int(data_date)
            except Exception:
                data_date_i = None

            try:
                data_time_i = int(data_time)
            except Exception:
                data_time_i = None

            if data_date_i is not None and data_time_i is not None:
                if data_date_i == expected_date and data_time_i == expected_time:
                    saw_expected_date_time = True
                else:
                    saw_wrong_date_time = True

            msg_end_hour = _parse_grib_message_end_hour_for_validation(grb)
            if msg_end_hour is not None:
                saw_any_fhr_metadata = True
                if int(msg_end_hour) == expected_actual_fhr:
                    saw_expected_fhr = True

            if saw_expected_date_time and saw_expected_fhr:
                grbs.close()
                return True

    except Exception as e:
        if verbose:
            tqdm.write(f"Invalid RAP file scan failed: {path} | {e}")
        try:
            grbs.close()
        except Exception:
            pass
        return False

    try:
        grbs.close()
    except Exception:
        pass

    if not saw_any_message:
        if verbose:
            tqdm.write(f"Invalid RAP file has no readable GRIB messages: {path}")
        return False

    if saw_wrong_date_time and not saw_expected_date_time:
        if verbose:
            tqdm.write(
                f"Invalid RAP file wrong date/time: {path} | "
                f"expected {expected_date}/{expected_time:04d}"
            )
        return False

    # Be lenient if pygrib/eccodes exposes forecast hour oddly; the URL/filename encodes it.
    if saw_any_fhr_metadata and not saw_expected_fhr and verbose:
        tqdm.write(
            f"Warning: RAP GRIB opened but did not show expected actual fhr={expected_actual_fhr:02d}; "
            f"accepting by filename/URL: {path}"
        )

    return True


def _write_nam_download_debug(date_str, fhr, rows):
    if not RAP_DOWNLOAD_DEBUG or not rows:
        return
    try:
        os.makedirs(RAP_DOWNLOAD_DEBUG_DIR, exist_ok=True)
        out = os.path.join(RAP_DOWNLOAD_DEBUG_DIR, f"rap_download_{date_str}_valid{int(fhr):02d}.csv")
        pd.DataFrame(rows).to_csv(out, index=False)
    except Exception:
        pass


def _nam_forecast_candidate_urls(date_str, fhr):
    """
    Candidate public URLs for RAP 13-km CONUS forecast files.

    fhr is the desired valid-time offset from 12z.
    actual_file_fhr = fhr + RAP_FILE_FHR_OFFSET.

    Source split:
      - 2019 only: NCEI THREDDS catalog URL exactly using model-rap130-old, dataset id rap130-old
      - >= 2021-02-22: AWS noaa-rap-pds first, then public mirrors / recent NCEI
    """
    valid_offset_fhr = int(fhr)
    actual_fhr = valid_offset_fhr + RAP_FILE_FHR_OFFSET
    yyyymm = str(date_str)[:6]
    date_str = str(date_str)
    date_i = int(date_str)
    cycle = int(RAP_INIT_CYCLE_HOUR)

    urls = []

    ncei_filename = f"rap_130_{date_str}_{cycle:02d}00_{actual_fhr:03d}.grb2"

    # Historical THREDDS collection. Use 2019 only; skip partial 2020.
    if RAP_THREDDS_OLD_START <= date_i <= RAP_THREDDS_OLD_END:
        urls.append((
            "ncei-thredds-catalog-model-rap130-old",
            f"https://www.ncei.noaa.gov/thredds/catalog/model-rap130-old/{yyyymm}/{date_str}/catalog.html?dataset=rap130-old/{yyyymm}/{date_str}/{ncei_filename}"
        ))

    # AWS / mirrors for newer public cloud archive.
    if date_i >= RAP_AWS_PUBLIC_ARCHIVE_START:
        urls.append((
            "aws-noaa-rap-pds",
            f"https://noaa-rap-pds.s3.amazonaws.com/rap.{date_str}/rap.t{cycle:02d}z.awp130pgrbf{actual_fhr:02d}.grib2"
        ))

        urls.append((
            "gcp-rapid-refresh",
            f"https://storage.googleapis.com/rapid-refresh/rap.{date_str}/rap.t{cycle:02d}z.awp130pgrbf{actual_fhr:02d}.grib2"
        ))

        urls.append((
            "azure-noaarap",
            f"https://noaarap.blob.core.windows.net/rap/rap.{date_str}/rap.t{cycle:02d}z.awp130pgrbf{actual_fhr:02d}.grib2"
        ))

        urls.append((
            "ncei-thredds-model-rap130",
            f"https://www.ncei.noaa.gov/thredds/fileServer/model-rap130/{yyyymm}/{date_str}/{ncei_filename}"
        ))

    return urls


def _resolve_thredds_catalog_download_url(catalog_url, expected_filename=None):
    """
    Resolve an NCEI THREDDS catalog.html?dataset=... URL to a downloadable GRIB URL.

    The historical RAP catalog URL is kept exactly in the candidate list, then this
    resolver follows the catalog page and extracts the HTTPServer/fileServer access
    URL when present.

    If the access URL cannot be found, fall back to the THREDDS fileServer URL
    built from the dataset id in the catalog query string.
    """
    row_meta = {
        "catalog_url": catalog_url,
        "resolved_url": None,
        "resolver_error": None,
        "resolver_status_code": None,
    }

    try:
        response = safe_requests_get(catalog_url, timeout=RAP_DOWNLOAD_TIMEOUT, allow_redirects=True)
        row_meta["resolver_status_code"] = response.status_code

        if response.status_code != 200:
            row_meta["resolver_error"] = f"catalog HTTP {response.status_code}"
            return None, row_meta

        html_text = unescape(response.text)

        # Most THREDDS catalog pages include an HTTPServer link to /thredds/fileServer/<dataset_id>.
        href_patterns = [
            r'href=["\\\']([^"\\\']*/thredds/fileServer/[^"\\\']+\.grb2[^"\\\']*)["\\\']',
            r'href=["\\\']([^"\\\']*fileServer/[^"\\\']+\.grb2[^"\\\']*)["\\\']',
            r'(https?://www\.ncei\.noaa\.gov/thredds/fileServer/[^\\s"\\\'<>]+\.grb2)',
        ]

        for pat in href_patterns:
            matches = re.findall(pat, html_text)
            for href in matches:
                if expected_filename and expected_filename not in href:
                    continue

                if href.startswith("http"):
                    resolved = href
                elif href.startswith("/"):
                    resolved = "https://www.ncei.noaa.gov" + href
                else:
                    resolved = "https://www.ncei.noaa.gov/thredds/" + href.lstrip("./")

                row_meta["resolved_url"] = resolved
                return resolved, row_meta

        # Fallback: extract dataset=rap130-old/YYYYMM/YYYYMMDD/file.grb2 from the exact URL.
        dataset_match = re.search(r"[?&]dataset=([^&]+)", catalog_url)
        if dataset_match:
            dataset_id = dataset_match.group(1)
            resolved = f"https://www.ncei.noaa.gov/thredds/fileServer/{dataset_id}"
            row_meta["resolved_url"] = resolved
            row_meta["resolver_error"] = "No explicit HTTPServer href found; used dataset-id fileServer fallback"
            return resolved, row_meta

        row_meta["resolver_error"] = "No fileServer href or dataset query parameter found"
        return None, row_meta

    except Exception as e:
        row_meta["resolver_error"] = repr(e)
        return None, row_meta



def _rap_canonical_local_path(date_str, fhr, output_dir):
    """Canonical local filename used by the feature extractor for one RAP valid offset."""
    actual_fhr = int(fhr) + RAP_FILE_FHR_OFFSET
    return os.path.join(
        output_dir,
        f"rap_130_{str(date_str)}_{RAP_INIT_CYCLE_HOUR:02d}z_valid{int(fhr):02d}_f{actual_fhr:03d}.grib2"
    )


def _rap_cache_candidate_paths(date_str, fhr, output_dir=None):
    """
    Deterministic RAP cache candidates for files already downloaded by prior training runs.

    This intentionally avoids broad recursive scans of RAP_DIR because that can become slow on
    shared filesystems.  It checks the canonical v19+ name plus common original-source names.
    """
    date_str = str(date_str)
    yyyymm = date_str[:6]
    actual_fhr = int(fhr) + RAP_FILE_FHR_OFFSET
    cycle = int(RAP_INIT_CYCLE_HOUR)

    dirs = []
    for d in [output_dir, RAP_DIR, *list(RAP_CACHE_SEARCH_DIRS or [])]:
        if d and d not in dirs:
            dirs.append(d)

    names = [
        # Canonical local name used by our RAP09z feature scripts.
        f"rap_130_{date_str}_{cycle:02d}z_valid{int(fhr):02d}_f{actual_fhr:03d}.grib2",
        # Raw NCEI THREDDS filename.
        f"rap_130_{date_str}_{cycle:02d}00_{actual_fhr:03d}.grb2",
        f"rap_130_{date_str}_{cycle:02d}00_{actual_fhr:03d}.grib2",
        # Public-cloud RAP filename variants.
        f"rap.t{cycle:02d}z.awp130pgrbf{actual_fhr:02d}.grib2",
        f"rap.t{cycle:02d}z.awp130pgrbf{actual_fhr:03d}.grib2",
    ]

    candidates = []
    seen = set()
    for d in dirs:
        for name in names:
            p = os.path.join(d, name)
            if p not in seen:
                seen.add(p)
                candidates.append(p)

        # Some older experiments saved files under date subdirectories. Check only shallow,
        # date-specific locations to avoid a huge recursive glob.
        for sub in [date_str, yyyymm, os.path.join(yyyymm, date_str), os.path.join(date_str[:4], yyyymm, date_str)]:
            for name in names:
                p = os.path.join(d, sub, name)
                if p not in seen:
                    seen.add(p)
                    candidates.append(p)

    if RAP_CACHE_RECURSIVE_DATE_SEARCH:
        # Date-specific recursive fallback.  This is only pattern-based and only for the
        # exact date/cycle/fhr names above, so it is much safer than a broad "*.grib2" scan.
        recursive_dirs = []
        for d in [RAP_DIR, *list(RAP_CACHE_SEARCH_DIRS or [])]:
            if d and d not in recursive_dirs and os.path.exists(d):
                recursive_dirs.append(d)
        for d in recursive_dirs:
            for name in names:
                try:
                    for p in glob.glob(os.path.join(d, "**", name), recursive=True):
                        if p not in seen:
                            seen.add(p)
                            candidates.append(p)
                except Exception:
                    pass

    return candidates


def _place_cached_rap_file(candidate_path, local_path):
    """Place a validated cached RAP file at the canonical local path without redownloading."""
    if os.path.abspath(candidate_path) == os.path.abspath(local_path):
        return True

    os.makedirs(os.path.dirname(local_path), exist_ok=True)
    if os.path.exists(local_path):
        try:
            os.remove(local_path)
        except Exception:
            pass

    try:
        if RAP_CACHE_COPY_MODE.lower() == "hardlink":
            os.link(candidate_path, local_path)
        elif RAP_CACHE_COPY_MODE.lower() == "symlink":
            os.symlink(candidate_path, local_path)
        else:
            shutil.copy2(candidate_path, local_path)
        return True
    except Exception:
        try:
            shutil.copy2(candidate_path, local_path)
            return True
        except Exception as e:
            tqdm.write(f"  cached RAP reuse failed for {candidate_path} -> {local_path}: {e}")
            return False


def find_existing_valid_rap_cache(date_str, fhr, output_dir=None, verbose=False):
    """
    Return the first already-downloaded RAP file matching date/cycle/fhr that validates.
    Skips temp/invalid/zero-byte files.
    """
    if not RAP_REUSE_EXISTING_CACHE:
        return None

    for candidate in _rap_cache_candidate_paths(date_str, fhr, output_dir=output_dir):
        base = os.path.basename(candidate)
        if base.endswith((".tmp", ".invalid", ".idx")):
            continue
        if not os.path.exists(candidate):
            continue
        try:
            if os.path.getsize(candidate) < RAP_MIN_FILE_SIZE_BYTES:
                continue
        except Exception:
            continue
        if validate_nam_forecast_file(candidate, date_str, fhr, verbose=False):
            if verbose:
                tqdm.write(
                    f"  reusing cached RAP valid+{int(fhr):02d}h "
                    f"(RAP {RAP_INIT_CYCLE_HOUR:02d}z f{int(fhr) + RAP_FILE_FHR_OFFSET:02d}): {candidate}"
                )
            return candidate

    return None


def _download_one_nam_forecast(date_str, fhr, local_path):
    """
    Download and validate one RAP file for a desired 12z-relative valid-time offset.
    """
    tmp_path = local_path + ".tmp"
    try:
        if os.path.exists(tmp_path):
            os.remove(tmp_path)
    except Exception:
        pass

    debug_rows = []
    actual_fhr = int(fhr) + RAP_FILE_FHR_OFFSET

    for source_name, url in _nam_forecast_candidate_urls(date_str, fhr):
        row = {
            "date": date_str,
            "valid_offset_fhr": int(fhr),
            "actual_file_fhr": actual_fhr,
            "cycle": RAP_INIT_CYCLE_HOUR,
            "source": source_name,
            "url": url,
            "status_code": None,
            "content_type": None,
            "bytes": None,
            "final_url": None,
            "validated": False,
            "catalog_url": None,
            "resolved_url": None,
            "resolver_status_code": None,
            "resolver_error": None,
            "error": None,
        }

        try:
            request_url = url

            if "thredds-catalog" in source_name:
                expected_filename = f"rap_130_{date_str}_{RAP_INIT_CYCLE_HOUR:02d}00_{actual_fhr:03d}.grb2"
                resolved_url, resolver_meta = _resolve_thredds_catalog_download_url(url, expected_filename=expected_filename)
                row.update(resolver_meta)

                if not resolved_url:
                    debug_rows.append(row)
                    tqdm.write(f"      -> THREDDS catalog resolver failed: {resolver_meta.get('resolver_error')}")
                    continue

                request_url = resolved_url

            tqdm.write(
                f"    downloading valid+{int(fhr):02d}h "
                f"(RAP {RAP_INIT_CYCLE_HOUR:02d}z f{actual_fhr:02d}) from {source_name}: {request_url}"
            )
            response = safe_requests_get(request_url, stream=True, timeout=RAP_DOWNLOAD_TIMEOUT, allow_redirects=True)

            row["status_code"] = response.status_code
            row["content_type"] = response.headers.get("Content-Type")
            row["final_url"] = response.url

            if response.status_code != 200:
                tqdm.write(f"      -> HTTP {response.status_code}")
                debug_rows.append(row)
                continue

            total_bytes = 0
            with open(tmp_path, "wb") as f:
                for chunk in response.iter_content(chunk_size=1024 * 1024):
                    if chunk:
                        total_bytes += len(chunk)
                        f.write(chunk)

            row["bytes"] = total_bytes

            if total_bytes < RAP_MIN_FILE_SIZE_BYTES:
                tqdm.write(
                    f"      -> downloaded file too small ({total_bytes} bytes) for valid+{int(fhr):02d}h; removing temp file"
                )
                try:
                    os.remove(tmp_path)
                except Exception:
                    pass
                debug_rows.append(row)
                continue

            if validate_nam_forecast_file(tmp_path, date_str, fhr, verbose=True):
                os.replace(tmp_path, local_path)
                row["validated"] = True
                debug_rows.append(row)
                _write_nam_download_debug(date_str, fhr, debug_rows)
                tqdm.write(f"      -> saved/validated: {local_path}")
                return True

            tqdm.write(f"      -> downloaded file failed validation for valid+{int(fhr):02d}h")
            try:
                os.remove(tmp_path)
            except Exception:
                pass

            debug_rows.append(row)

        except Exception as e:
            row["error"] = repr(e)
            debug_rows.append(row)
            tqdm.write(f"      -> download failed from {source_name}: {e}")
            try:
                if os.path.exists(tmp_path):
                    os.remove(tmp_path)
            except Exception:
                pass

    _write_nam_download_debug(date_str, fhr, debug_rows)
    return False


def ensure_nam_forecast_file(date_str, fhr, output_dir):
    """
    Ensure one validated RAP file exists locally for a desired valid offset from 12z.

    Order of operations:
      1. validate canonical local file
      2. reuse/copy/hardlink any already-downloaded equivalent RAP cache file
      3. only then attempt network download

    This prevents v26 from redownloading RAP files that earlier v19-v23 runs already cached.
    """
    os.makedirs(output_dir, exist_ok=True)
    local_path = _rap_canonical_local_path(date_str, fhr, output_dir)
    tmp_path = local_path + ".tmp"

    # Never let an old failed 0-byte temp file confuse this run.
    if os.path.exists(tmp_path):
        try:
            os.remove(tmp_path)
        except Exception:
            pass

    if validate_nam_forecast_file(local_path, date_str, fhr):
        return local_path

    cached = find_existing_valid_rap_cache(date_str, fhr, output_dir=output_dir, verbose=True)
    if cached and _place_cached_rap_file(cached, local_path):
        return local_path

    if os.path.exists(local_path):
        bad_path = local_path + ".invalid"
        try:
            os.replace(local_path, bad_path)
            tqdm.write(f"  moved invalid RAP file aside: {bad_path}")
        except Exception:
            try:
                os.remove(local_path)
            except Exception:
                pass

    if not RAP_ALLOW_NETWORK_DOWNLOADS:
        tqdm.write(
            f"  RAP network downloads disabled; no local/cache RAP file found for {date_str} valid+{int(fhr):02d}h"
        )
        return None

    if _download_one_nam_forecast(date_str, fhr, local_path):
        return local_path

    return None

def download_nam_forecasts_osdf(date_str, output_dir, show_progress=False):
    """
    Download/validate RAP 09z files mapped onto 12z-relative feature offsets.
    """
    os.makedirs(output_dir, exist_ok=True)

    files_dict = {}

    fhr_iter = FORECAST_HOURS
    if show_progress:
        fhr_iter = tqdm(FORECAST_HOURS, desc=f"RAP {date_str} files", unit="valid_fhr", leave=False)

    for fhr in fhr_iter:
        local_path = _rap_canonical_local_path(date_str, fhr, output_dir)
        files_dict[f"fhr_{int(fhr):02d}h"] = local_path
        ensured_path = ensure_nam_forecast_file(date_str, fhr, output_dir)
        if ensured_path is None:
            tqdm.write(
                f"  RAP valid+{int(fhr):02d}h unavailable after cache check + download attempt: {local_path}"
            )

    return files_dict





def _as_list(value):
    if isinstance(value, (list, tuple, set)):
        return list(value)
    return [value]


def _norm_grib_text(value):
    return str(value).upper().replace(" ", "").strip()


def get_nam_variable_value(grbs, short_names, level_types, level_target=None):
    """
    Flexible GRIB lookup.

    short_names:
        str or list[str], e.g., ["U", "UGRD"].
    level_types:
        str or list[str], normalized and matched by exact equality OR substring.
        The substring fallback helps with pygrib naming differences.
    level_target:
        int/float or None. If None, the first matching level is used.
    """
    wanted_short_names = {_norm_grib_text(x) for x in _as_list(short_names)}
    wanted_level_types = {_norm_grib_text(x) for x in _as_list(level_types)}

    try:
        # pygrib iterators are consumed after iteration, so rewind before every lookup.
        try:
            grbs.seek(0)
        except Exception:
            pass

        for grb in grbs:
            s_name = _norm_grib_text(getattr(grb, "shortName", ""))
            l_type = _norm_grib_text(getattr(grb, "typeOfLevel", ""))

            if s_name not in wanted_short_names:
                continue

            level_type_match = any(
                l_type == target_ltype
                or target_ltype in l_type
                or l_type in target_ltype
                for target_ltype in wanted_level_types
            )

            if not level_type_match:
                continue

            if level_target is None:
                return grb.values

            try:
                grb_level = int(float(grb.level))
                wanted_levels = [int(float(x)) for x in _as_list(level_target)]
                if grb_level in wanted_levels:
                    return grb.values
            except Exception:
                continue

    except Exception:
        pass

    return None


def fetch_iem_flash_flood_reports_pixel(date_str, lats_1d, lons_1d, domain_mask_2d, lats_2d):
    base_dt = datetime.strptime(date_str, "%Y%m%d") + timedelta(hours=12)
    end_dt = base_dt + timedelta(hours=24)

    sts = base_dt.strftime("%Y-%m-%dT%H:%M") + "Z"
    ets = end_dt.strftime("%Y-%m-%dT%H:%M") + "Z"

    min_lat, max_lat = float(np.min(lats_1d)), float(np.max(lats_1d))
    min_lon, max_lon = float(np.min(lons_1d)), float(np.max(lons_1d))

    url = (
        "https://mesonet.agron.iastate.edu/geojson/lsr.geojson"
        f"?west={min_lon}&east={max_lon}&north={max_lat}&south={min_lat}&sts={sts}&ets={ets}"
    )

    target_1d = np.zeros(len(lats_1d), dtype=np.int8)

    try:
        req = safe_requests_get(url, timeout=10)

        if req.status_code == 200:
            data = req.json()

            if "features" in data:
                report_coords = []

                for feature in data["features"]:
                    props = feature.get("properties", {})

                    if props.get("typetext", "").upper() in ["FLASH FLOOD", "FLOOD", "HEAVY RAIN"]:
                        coords = feature.get("geometry", {}).get("coordinates", [])

                        if len(coords) >= 2:
                            report_coords.append([coords[1], coords[0]])

                if report_coords:
                    tree = cKDTree(np.column_stack((lats_1d, lons_1d)))
                    idxs = tree.query_ball_point(report_coords, r=0.15)

                    for idx_list in idxs:
                        if len(idx_list) > 0:
                            target_1d[idx_list] = 1
    except Exception:
        pass

    target_2d = np.zeros(lats_2d.shape, dtype=np.int8)
    target_2d[domain_mask_2d] = target_1d

    # Spatially expand reports to nearby NAM pixels.
    target_2d = maximum_filter(target_2d, size=3)

    return target_2d[domain_mask_2d]



