def _download_to_path(url, local_path, timeout, min_bytes=1024):
    """Download URL to local_path atomically. Returns True on a valid non-empty file."""
    os.makedirs(os.path.dirname(local_path), exist_ok=True)

    if os.path.exists(local_path) and os.path.getsize(local_path) >= int(min_bytes):
        return True

    tmp_path = local_path + ".tmp"
    if os.path.exists(tmp_path):
        try:
            os.remove(tmp_path)
        except Exception:
            pass

    try:
        r = safe_requests_get(url, stream=True, timeout=timeout, allow_redirects=True)
        if r.status_code != 200:
            return False

        total = 0
        with open(tmp_path, "wb") as f:
            for chunk in r.iter_content(chunk_size=1024 * 1024):
                if chunk:
                    total += len(chunk)
                    f.write(chunk)

        if total < int(min_bytes):
            try:
                os.remove(tmp_path)
            except Exception:
                pass
            return False

        os.replace(tmp_path, local_path)
        return True

    except Exception:
        try:
            if os.path.exists(tmp_path):
                os.remove(tmp_path)
        except Exception:
            pass
        return False


def _gunzip_to_path(gz_path, out_path, min_bytes=1024):
    if os.path.exists(out_path) and os.path.getsize(out_path) >= int(min_bytes):
        return True
    tmp_path = out_path + ".tmp"
    try:
        with gzip.open(gz_path, "rb") as f_in, open(tmp_path, "wb") as f_out:
            shutil.copyfileobj(f_in, f_out)
        if os.path.getsize(tmp_path) < int(min_bytes):
            os.remove(tmp_path)
            return False
        os.replace(tmp_path, out_path)
        return True
    except Exception:
        try:
            if os.path.exists(tmp_path):
                os.remove(tmp_path)
        except Exception:
            pass
        return False


def _validate_grib_file(path, min_bytes=1024):
    if not path or not os.path.exists(path):
        return False
    try:
        if os.path.getsize(path) < int(min_bytes):
            return False
        grbs = pygrib.open(path)
        _ = grbs.message(1)
        grbs.close()
        return True
    except Exception:
        try:
            grbs.close()
        except Exception:
            pass
        return False


def _mrms_filename(dt, product, *, ncep_realtime=False):
    """Return MRMS QPE filename for either IEM archive or NCEP realtime naming.

    IEM/MTArchive archived files do NOT include the leading ``MRMS_`` prefix:
        MultiSensor_QPE_01H_Pass2_00.00_YYYYMMDD-HH0000.grib2.gz
        GaugeCorr_QPE_01H_00.00_YYYYMMDD-HH0000.grib2.gz

    NCEP realtime files DO include the leading ``MRMS_`` prefix:
        MRMS_MultiSensor_QPE_01H_Pass2_00.00_YYYYMMDD-HH0000.grib2.gz
    """
    stamp = dt.strftime("%Y%m%d-%H0000")
    fname = f"{product}_00.00_{stamp}.grib2"
    if ncep_realtime:
        fname = "MRMS_" + fname
    return fname


def _mrms_iem_mtarchive_url(dt, product):
    y = dt.strftime("%Y")
    m = dt.strftime("%m")
    d = dt.strftime("%d")
    fname = _mrms_filename(dt, product, ncep_realtime=False)
    return (
        f"{MRMS_IEM_MTARCHIVE_BASE}/{y}/{m}/{d}/mrms/ncep/{product}/{fname}.gz",
        fname,
    )


def _mrms_ncsu_thredds_url(dt, product):
    """NCSU/NCEI THREDDS archive URL and local filename for one hourly MRMS QPE file."""
    yyyymm = dt.strftime("%Y%m")
    yyyymmdd = dt.strftime("%Y%m%d")
    fname = _mrms_filename(dt, product, ncep_realtime=True)  # NCSU files include leading MRMS_
    return (
        f"{MRMS_NCSU_THREDDS_BASE}/{yyyymm}/{yyyymmdd}/{fname}",
        fname,
    )


def _mrms_candidate_urls(dt):
    """
    Candidate MRMS 1-h observed QPE URLs.

    v26 archive order:
      1. local cache handled before this function
      2. IEM/MTArchive archived MRMS (fastest when present)
      3. NCSU/NCEI THREDDS archived MRMS (fills 2018/early-2019 and many other gaps)
      4. NCEP realtime rolling directory only as last-resort realtime fallback

    IEM/MTArchive files do not include the leading MRMS_ prefix; NCSU/NCEI and NCEP realtime do.
    """
    candidates = []

    if dt.year <= 2020:
        product_order = [MRMS_LEGACY_PRODUCT, MRMS_PRIMARY_PRODUCT]
    else:
        product_order = [MRMS_PRIMARY_PRODUCT, MRMS_LEGACY_PRODUCT]

    # Fast archive first when present. IEM notes its raw MRMS archive is most useful for the
    # Sep-2019 to Oct-2020 gap; outside that window this will just 404 quickly.
    for product in product_order:
        url, fname = _mrms_iem_mtarchive_url(dt, product)
        candidates.append((f"iem-mtarchive-{product}", url, fname))

    # More complete historical archive. This is the important v26 fix for dates that v24d skipped.
    if MRMS_USE_NCSU_THREDDS_ARCHIVE:
        for product in product_order:
            url, fname = _mrms_ncsu_thredds_url(dt, product)
            candidates.append((f"ncsu-ncei-thredds-{product}", url, fname))

    if MRMS_ALLOW_REALTIME_NCEP_FALLBACK:
        pass2_realtime = _mrms_filename(dt, MRMS_PRIMARY_PRODUCT, ncep_realtime=True)
        legacy_realtime = _mrms_filename(dt, MRMS_LEGACY_PRODUCT, ncep_realtime=True)
        candidates.extend([
            (
                "ncep-realtime-pass2-no-data-prefix",
                f"https://mrms.ncep.noaa.gov/2D/{MRMS_PRIMARY_PRODUCT}/{pass2_realtime}.gz",
                pass2_realtime,
            ),
            (
                "ncep-realtime-pass2-data-prefix",
                f"https://mrms.ncep.noaa.gov/data/2D/{MRMS_PRIMARY_PRODUCT}/{pass2_realtime}.gz",
                pass2_realtime,
            ),
            (
                "ncep-realtime-legacy-gaugecorr-data-prefix",
                f"https://mrms.ncep.noaa.gov/data/2D/{MRMS_LEGACY_PRODUCT}/{legacy_realtime}.gz",
                legacy_realtime,
            ),
        ])

    return candidates

def ensure_mrms_qpe_1h_file(dt):
    date_dir = os.path.join(MRMS_QPE_DIR, dt.strftime("%Y%m%d"))
    os.makedirs(date_dir, exist_ok=True)

    # Check known local forms first.  Support both IEM archive names and older cached
    # NCEP realtime names from v24.
    for product in [MRMS_PRIMARY_PRODUCT, MRMS_LEGACY_PRODUCT]:
        for realtime_name in [False, True]:
            fname = _mrms_filename(dt, product, ncep_realtime=realtime_name)
            local = os.path.join(date_dir, fname)
            if _validate_grib_file(local, MRMS_MIN_FILE_SIZE_BYTES):
                return local

    debug_rows = []
    for source_name, url, fname in _mrms_candidate_urls(dt):
        local = os.path.join(date_dir, fname)
        gz_local = local + ".gz"
        row = {"datetime": dt.isoformat(), "source": source_name, "url": url, "local": local}

        if _validate_grib_file(local, MRMS_MIN_FILE_SIZE_BYTES):
            row["used_cached"] = True
            debug_rows.append(row)
            return local

        if url.endswith(".gz"):
            ok = _download_to_path(url, gz_local, MRMS_DOWNLOAD_TIMEOUT, min_bytes=MRMS_MIN_FILE_SIZE_BYTES)
            row["download_gz_ok"] = bool(ok)
            if ok:
                ok2 = _gunzip_to_path(gz_local, local, min_bytes=MRMS_MIN_FILE_SIZE_BYTES)
                row["gunzip_ok"] = bool(ok2)
                if ok2 and _validate_grib_file(local, MRMS_MIN_FILE_SIZE_BYTES):
                    debug_rows.append(row)
                    return local
        else:
            ok = _download_to_path(url, local, MRMS_DOWNLOAD_TIMEOUT, min_bytes=MRMS_MIN_FILE_SIZE_BYTES)
            row["download_ok"] = bool(ok)
            if ok and _validate_grib_file(local, MRMS_MIN_FILE_SIZE_BYTES):
                debug_rows.append(row)
                return local

        debug_rows.append(row)

    try:
        dbg = os.path.join(HYDRO_TARGET_DEBUG_DIR, f"mrms_qpe_download_{dt.strftime('%Y%m%d%H')}.csv")
        pd.DataFrame(debug_rows).to_csv(dbg, index=False)
    except Exception:
        pass

    return None


def _ffg_candidate_urls(cycle_dt):
    y = cycle_dt.strftime("%Y")
    m = cycle_dt.strftime("%m")
    d = cycle_dt.strftime("%d")
    stamp = cycle_dt.strftime("%Y%m%d%H")
    rel = f"archive/data/{y}/{m}/{d}/model/ffg/5kmffg_{stamp}.grib2"
    return [
        ("iem-primary", f"https://mesonet.agron.iastate.edu/{rel}"),
        ("iem-secondary", f"https://mesonet2.agron.iastate.edu/{rel}"),
    ]


def ensure_ffg_file_at_or_before(valid_dt):
    """
    Use the latest 6-hourly FFG file at or before the start of the observed QPE window.
    This avoids using future FFG guidance relative to the interval being verified.
    """
    floored_hour = (int(valid_dt.hour) // 6) * 6
    cycle_dt = valid_dt.replace(hour=floored_hour, minute=0, second=0, microsecond=0)

    for back_hours in range(0, int(FFG_LOOKBACK_HOURS) + 1, 6):
        cand_dt = cycle_dt - timedelta(hours=back_hours)
        date_dir = os.path.join(FFG_DIR, cand_dt.strftime("%Y%m%d"))
        os.makedirs(date_dir, exist_ok=True)
        local = os.path.join(date_dir, f"5kmffg_{cand_dt.strftime('%Y%m%d%H')}.grib2")

        if _validate_grib_file(local, FFG_MIN_FILE_SIZE_BYTES):
            return local

        for source_name, url in _ffg_candidate_urls(cand_dt):
            if _download_to_path(url, local, FFG_DOWNLOAD_TIMEOUT, min_bytes=FFG_MIN_FILE_SIZE_BYTES):
                if _validate_grib_file(local, FFG_MIN_FILE_SIZE_BYTES):
                    return local

    return None


def _as_float_grid_from_grib(grb):
    vals = grb.values
    if np.ma.isMaskedArray(vals):
        arr = vals.filled(np.nan).astype(np.float32)
    else:
        arr = np.asarray(vals, dtype=np.float32)
    arr = np.where(arr <= -9000.0, np.nan, arr)
    return arr.astype(np.float32, copy=False)


def _infer_ffg_duration_hours(grb, msg_index=None):
    fields = []
    for key in ["name", "shortName", "parameterName", "parameterNameECMF", "stepRange", "stepType"]:
        val = _safe_grib_key(grb, key, None)
        if val is not None:
            fields.append(str(val))
    txt = " ".join(fields).lower()

    # Strong text match first.
    patterns = [
        (1, ["1 hour", "1-hour", "01 hour", "01-hour", "1hr", "01hr", "ffg01", "ffg_01"]),
        (3, ["3 hour", "3-hour", "03 hour", "03-hour", "3hr", "03hr", "ffg03", "ffg_03"]),
        (6, ["6 hour", "6-hour", "06 hour", "06-hour", "6hr", "06hr", "ffg06", "ffg_06"]),
        (12, ["12 hour", "12-hour", "12hr", "ffg12", "ffg_12"]),
        (24, ["24 hour", "24-hour", "24hr", "ffg24", "ffg_24"]),
    ]
    for dur, pats in patterns:
        if any(p in txt for p in pats):
            return dur

    # GRIB step/end metadata fallback.
    for key in ["endStep", "forecastTime", "forecastTimeInHours"]:
        val = _safe_grib_key(grb, key, None)
        if val is not None:
            try:
                dur = int(float(str(val).split("-")[-1]))
                if dur in [1, 3, 6, 12, 24]:
                    return dur
            except Exception:
                pass

    step_range = _safe_grib_key(grb, "stepRange", None)
    if step_range is not None:
        vals = re.findall(r"\d+", str(step_range))
        if vals:
            try:
                dur = int(vals[-1])
                if dur in [1, 3, 6, 12, 24]:
                    return dur
            except Exception:
                pass

    # Common FFG message order fallback.
    if msg_index is not None:
        order = [1, 3, 6, 12, 24]
        i = int(msg_index) - 1
        if 0 <= i < len(order):
            return order[i]

    return None


def _maybe_convert_ffg_to_mm(arr, grb):
    units = str(_safe_grib_key(grb, "units", "")).lower()
    out = arr.astype(np.float32, copy=True)

    if "inch" in units or units.strip() in {"in", "in."}:
        return out * np.float32(25.4), "in_to_mm_units"

    if FFG_AUTO_CONVERT_INCHES_TO_MM:
        finite = out[np.isfinite(out) & (out > 0)]
        if finite.size:
            p95 = float(np.nanpercentile(finite, 95))
            # FFG values in inches are commonly single-digit.  Values in mm are usually much larger.
            if p95 <= 12.0:
                return out * np.float32(25.4), "in_to_mm_auto_p95_le_12"

    return out, "as_is"


def read_ffg_duration_grids(path):
    """Return {duration_h: grid_mm}, plus write a small metadata CSV for debugging."""
    duration_grids = {}
    rows = []
    grbs = None
    try:
        grbs = pygrib.open(path)
        for i, grb in enumerate(grbs, start=1):
            dur = _infer_ffg_duration_hours(grb, msg_index=i)
            arr = _as_float_grid_from_grib(grb)
            arr, conversion = _maybe_convert_ffg_to_mm(arr, grb)
            rows.append({
                "file": os.path.basename(path),
                "message": i,
                "inferred_duration_h": dur,
                "shortName": _safe_grib_key(grb, "shortName", None),
                "name": _safe_grib_key(grb, "name", None),
                "units": _safe_grib_key(grb, "units", None),
                "stepRange": _safe_grib_key(grb, "stepRange", None),
                "conversion": conversion,
                "finite_frac": float(np.isfinite(arr).mean()),
                "min": float(np.nanmin(arr)) if np.isfinite(arr).any() else np.nan,
                "max": float(np.nanmax(arr)) if np.isfinite(arr).any() else np.nan,
                "mean": float(np.nanmean(arr)) if np.isfinite(arr).any() else np.nan,
            })
            # Read all target + predictor FFG durations.  The observed target still only
            # uses TARGET_DURATIONS_H, while guidance predictors may include 12/24h FFG.
            allowed_durs = globals().get("ALL_FFG_READ_DURATIONS_H", TARGET_DURATIONS_H)
            if dur in allowed_durs and dur not in duration_grids:
                duration_grids[int(dur)] = arr.astype(np.float32, copy=False)
    finally:
        try:
            if grbs is not None:
                grbs.close()
        except Exception:
            pass

    try:
        dbg = os.path.join(HYDRO_TARGET_DEBUG_DIR, f"ffg_messages_{os.path.basename(path)}.csv")
        if not os.path.exists(dbg):
            pd.DataFrame(rows).to_csv(dbg, index=False)
    except Exception:
        pass

    return duration_grids


def _read_grib_grid(path, include_latlon=False):
    grbs = None
    try:
        grbs = pygrib.open(path)
        grb = grbs.message(1)
        arr = _as_float_grid_from_grib(grb)
        if include_latlon:
            lats, lons = grb.latlons()
            lons = np.where(lons > 180.0, lons - 360.0, lons)
            return arr, lats.astype(np.float32), lons.astype(np.float32)
        return arr
    finally:
        try:
            if grbs is not None:
                grbs.close()
        except Exception:
            pass


def _regular_grid_nearest_flat_indices(src_lats_2d, src_lons_2d, target_lats_1d, target_lons_1d):
    """Fast nearest-neighbor mapper for regular lat/lon grids; falls back to KDTree if needed."""
    src_lons_2d = np.where(src_lons_2d > 180.0, src_lons_2d - 360.0, src_lons_2d)
    ny, nx = src_lats_2d.shape

    lat_axis = np.asarray(src_lats_2d[:, 0], dtype=np.float64)
    lon_axis = np.asarray(src_lons_2d[0, :], dtype=np.float64)

    lat_monotonic = np.all(np.diff(lat_axis) > 0) or np.all(np.diff(lat_axis) < 0)
    lon_monotonic = np.all(np.diff(lon_axis) > 0) or np.all(np.diff(lon_axis) < 0)

    if lat_monotonic and lon_monotonic:
        lat_rev = np.diff(lat_axis).mean() < 0
        lon_rev = np.diff(lon_axis).mean() < 0

        lat_sorted = lat_axis[::-1] if lat_rev else lat_axis
        lon_sorted = lon_axis[::-1] if lon_rev else lon_axis

        def nearest_sorted(axis, values):
            pos = np.searchsorted(axis, values)
            pos0 = np.clip(pos - 1, 0, len(axis) - 1)
            pos1 = np.clip(pos, 0, len(axis) - 1)
            choose1 = np.abs(axis[pos1] - values) < np.abs(axis[pos0] - values)
            return np.where(choose1, pos1, pos0)

        iy_sorted = nearest_sorted(lat_sorted, np.asarray(target_lats_1d, dtype=np.float64))
        ix_sorted = nearest_sorted(lon_sorted, np.asarray(target_lons_1d, dtype=np.float64))

        iy = (ny - 1 - iy_sorted) if lat_rev else iy_sorted
        ix = (nx - 1 - ix_sorted) if lon_rev else ix_sorted
        return (iy.astype(np.int64) * int(nx) + ix.astype(np.int64)).astype(np.int64)

    # Fallback for non-regular grids.  This can be expensive for MRMS, but should rarely be needed.
    tree = cKDTree(np.column_stack((src_lats_2d.ravel(), src_lons_2d.ravel())))
    _, idx = tree.query(np.column_stack((target_lats_1d, target_lons_1d)), k=1)
    return idx.astype(np.int64)


_GRID_SAMPLE_INDEX_CACHE = {}
_FFG_DURATION_GRID_CACHE = {}


def _hazml_nanmin_no_allnan_warning_v26f(stack, axis=0):
    """np.nanmin without RuntimeWarning for all-NaN slices."""
    all_nan = np.all(np.isnan(stack), axis=axis)
    tmp = np.where(np.isnan(stack), np.inf, stack)
    out = np.min(tmp, axis=axis)
    out = np.where(all_nan, np.nan, out)
    return out


def _hazml_nanmax_no_allnan_warning_v26f(stack, axis=0):
    """np.nanmax without RuntimeWarning for all-NaN slices."""
    all_nan = np.all(np.isnan(stack), axis=axis)
    tmp = np.where(np.isnan(stack), -np.inf, stack)
    out = np.max(tmp, axis=axis)
    out = np.where(all_nan, np.nan, out)
    return out


# Backward-compatible aliases in case any older patched block still calls the v26c names.
_hazml_nanmin_no_allnan_warning_v26c = _hazml_nanmin_no_allnan_warning_v26f
_hazml_nanmax_no_allnan_warning_v26c = _hazml_nanmax_no_allnan_warning_v26f


def _sample_grid_to_domain(grid, src_lats, src_lons, target_lats_1d, target_lons_1d, cache_key):
    key = (cache_key, tuple(grid.shape), len(target_lats_1d))
    flat_idx = _GRID_SAMPLE_INDEX_CACHE.get(key)
    if flat_idx is None:
        flat_idx = _regular_grid_nearest_flat_indices(src_lats, src_lons, target_lats_1d, target_lons_1d)
        _GRID_SAMPLE_INDEX_CACHE[key] = flat_idx
    return grid.ravel()[flat_idx].astype(np.float32, copy=False)


def _get_ffg_sampled(path, duration_h, target_lats_1d, target_lons_1d):
    key = (path, int(duration_h), len(target_lats_1d))
    cached = _FFG_DURATION_GRID_CACHE.get(key)
    if cached is not None:
        return cached

    grids = read_ffg_duration_grids(path)
    grid = grids.get(int(duration_h))
    if grid is None:
        return None

    # Need lat/lon from the same file.  Use the message matching duration if possible.
    grbs = None
    try:
        grbs = pygrib.open(path)
        chosen = None
        for i, grb in enumerate(grbs, start=1):
            if _infer_ffg_duration_hours(grb, msg_index=i) == int(duration_h):
                chosen = grb
                break
        if chosen is None:
            grbs.seek(0)
            chosen = grbs.message(1)
        ffg_lats, ffg_lons = chosen.latlons()
        ffg_lons = np.where(ffg_lons > 180.0, ffg_lons - 360.0, ffg_lons)
    finally:
        try:
            if grbs is not None:
                grbs.close()
        except Exception:
            pass

    sampled = _sample_grid_to_domain(
        grid=grid,
        src_lats=ffg_lats.astype(np.float32),
        src_lons=ffg_lons.astype(np.float32),
        target_lats_1d=target_lats_1d,
        target_lons_1d=target_lons_1d,
        cache_key="ffg5km",
    )
    _FFG_DURATION_GRID_CACHE[key] = sampled
    return sampled


def build_guidance_ffg_predictors(date_str, lats_1d, lons_1d, row_idx=None, keep_mask_1d=None):
    """
    Build realtime-available FFG guidance predictors for model fitting/inference.

    These are safe predictors because they use the latest 1/3/6/12/24h FFG guidance at or
    before the RAP initialization time for the case date. They are not observed
    verification fields and should not be dropped by the leakage guard.

    Parameters
    ----------
    date_str : str/int
        Case date, YYYYMMDD.
    lats_1d, lons_1d : array-like
        Full domain latitude/longitude arrays.
    row_idx : array-like or None
        Optional row indices used when reusing a prior RAP feature chunk whose rows
        map back to the full domain.
    keep_mask_1d : array-like bool or None
        Optional mask used by fresh extraction after land/domain filtering.
    """
    if not USE_GUIDANCE_FFG_FEATURES:
        return {}

    n_full = len(lats_1d)
    if row_idx is not None:
        select = np.asarray(row_idx, dtype=np.int64)
    elif keep_mask_1d is not None:
        select = np.asarray(keep_mask_1d, dtype=bool)
    else:
        select = slice(None)

    try:
        init_dt = datetime.strptime(str(date_str), "%Y%m%d") + timedelta(hours=int(GUIDANCE_FFG_INIT_RELATIVE_HOUR))
    except Exception:
        init_dt = datetime.strptime(str(date_str)[:8], "%Y%m%d") + timedelta(hours=int(GUIDANCE_FFG_INIT_RELATIVE_HOUR))

    ffg_path = ensure_ffg_file_at_or_before(init_dt)
    out = {}
    sampled_by_dur = {}

    for duration_h in GUIDANCE_FFG_DURATIONS_H:
        tag = _target_duration_tag(duration_h)
        col = f"Guide_FFG_{tag}_mm"
        vals_full = None
        if ffg_path is not None:
            try:
                vals_full = _get_ffg_sampled(
                    path=ffg_path,
                    duration_h=int(duration_h),
                    target_lats_1d=lats_1d,
                    target_lons_1d=lons_1d,
                )
            except Exception as e:
                tqdm.write(f"{date_str}: guidance FFG {tag} sampling failed: {e}")
                vals_full = None

        if vals_full is None:
            vals_full = np.full(n_full, np.nan, dtype=np.float32)
        else:
            vals_full = np.asarray(vals_full, dtype=np.float32)
            vals_full = np.where(vals_full >= float(GUIDANCE_FFG_MIN_VALID_MM), vals_full, np.nan).astype(np.float32)

        sampled_by_dur[int(duration_h)] = vals_full
        out[col] = vals_full[select].astype(np.float32, copy=False)

    have_arrays = [sampled_by_dur[int(d)] for d in GUIDANCE_FFG_DURATIONS_H if int(d) in sampled_by_dur]
    if have_arrays:
        stack = np.vstack(have_arrays).astype(np.float32)
        with np.errstate(all="ignore"):
            out["Guide_FFG_Min_1_3_6_12_24h_mm"] = _hazml_nanmin_no_allnan_warning_v26f(stack, axis=0)[select].astype(np.float32, copy=False)
            out["Guide_FFG_Max_1_3_6_12_24h_mm"] = _hazml_nanmax_no_allnan_warning_v26f(stack, axis=0)[select].astype(np.float32, copy=False)
            out["Guide_FFG_Mean_1_3_6_12_24h_mm"] = np.nanmean(stack, axis=0)[select].astype(np.float32, copy=False)
            out["Guide_FFG_Std_1_3_6_12_24h_mm"] = np.nanstd(stack, axis=0)[select].astype(np.float32, copy=False)

    if 1 in sampled_by_dur and 6 in sampled_by_dur:
        out["Guide_FFG_06h_to_01h_Ratio"] = (
            sampled_by_dur[6] / np.maximum(sampled_by_dur[1], np.float32(0.01))
        )[select].astype(np.float32, copy=False)

    if ffg_path is not None:
        out["Guide_FFG_FileCycleHour"] = np.full(len(next(iter(out.values()))), _cycle_hour_from_ffg_filename(ffg_path), dtype=np.float32)

    return out


def _cycle_hour_from_ffg_filename(path):
    m = re.search(r"5kmffg_(\d{10})", os.path.basename(str(path)))
    if not m:
        return np.nan
    try:
        return float(m.group(1)[-2:])
    except Exception:
        return np.nan


def _table_len(table):
    if isinstance(table, pd.DataFrame):
        return len(table)
    if not table:
        return 0
    return len(next(iter(table.values())))


def _nan_stat_no_warning(arrs, stat):
    valid = [np.asarray(a, dtype=np.float32) for a in arrs if a is not None]
    if not valid:
        return None
    stack = np.vstack(valid).astype(np.float32)
    if stat == "mean":
        return np.nanmean(stack, axis=0).astype(np.float32)
    if stat == "std":
        return np.nanstd(stack, axis=0).astype(np.float32)
    if stat == "min":
        return _hazml_nanmin_no_allnan_warning_v26f(stack, axis=0).astype(np.float32)
    if stat == "max":
        return _hazml_nanmax_no_allnan_warning_v26f(stack, axis=0).astype(np.float32)
    raise ValueError(stat)


def add_period_summary_features(table):
    """Add mean/min/max/std summaries across forecast periods/durations."""
    if not USE_PERIOD_SUMMARY_FEATURES:
        return table

    def _has(col):
        return col in table

    def _arr(col):
        return np.asarray(table[col], dtype=np.float32)

    def _put(col, vals):
        vals = np.asarray(vals, dtype=np.float32)
        if isinstance(table, pd.DataFrame):
            table[col] = vals
        else:
            table[col] = vals

    groups = {
        "Forecast_APCP_RunningTotals_0to6_0to12_0to18_0to24h_mm": [
            "APCP_RunTotal_0_06h", "APCP_RunTotal_0_12h", "APCP_RunTotal_0_18h", "APCP_RunTotal_0_24h"
        ],
        "Forecast_APCP_6hIntervals_0to24h_mm": [
            "APCP_Interval_00_06h", "APCP_Interval_06_12h", "APCP_Interval_12_18h", "APCP_Interval_18_24h"
        ],
        "Guidance_FFG_1h3h6h12h24h_mm": [
            "Guide_FFG_01h_mm", "Guide_FFG_03h_mm", "Guide_FFG_06h_mm", "Guide_FFG_12h_mm", "Guide_FFG_24h_mm"
        ],
    }

    for prefix, cols in groups.items():
        arrs = [_arr(c) for c in cols if _has(c)]
        if not arrs:
            continue
        for stat_name, stat in [("Mean", "mean"), ("Min", "min"), ("Max", "max"), ("Std", "std")]:
            vals = _nan_stat_no_warning(arrs, stat)
            if vals is not None:
                _put(f"{prefix}_{stat_name}", vals)

    # Max duration-matched QPF windows from available 6-hour intervals/running totals.
    if all(_has(c) for c in ["APCP_Interval_00_06h", "APCP_Interval_06_12h", "APCP_Interval_12_18h", "APCP_Interval_18_24h"]):
        i00 = _arr("APCP_Interval_00_06h")
        i06 = _arr("APCP_Interval_06_12h")
        i12 = _arr("APCP_Interval_12_18h")
        i18 = _arr("APCP_Interval_18_24h")
        _put("Forecast_APCP_Max_6h_Window_0to24h_mm", _nan_stat_no_warning([i00, i06, i12, i18], "max"))
        _put("Forecast_APCP_Max_12h_Window_0to24h_mm", _nan_stat_no_warning([i00 + i06, i06 + i12, i12 + i18], "max"))
    elif all(_has(c) for c in ["APCP_RunTotal_0_06h", "APCP_RunTotal_0_12h", "APCP_RunTotal_0_18h", "APCP_RunTotal_0_24h"]):
        r06 = _arr("APCP_RunTotal_0_06h")
        r12 = _arr("APCP_RunTotal_0_12h")
        r18 = _arr("APCP_RunTotal_0_18h")
        r24 = _arr("APCP_RunTotal_0_24h")
        i00 = r06
        i06 = np.clip(r12 - r06, 0, None)
        i12 = np.clip(r18 - r12, 0, None)
        i18 = np.clip(r24 - r18, 0, None)
        _put("Forecast_APCP_Max_6h_Window_0to24h_mm", _nan_stat_no_warning([i00, i06, i12, i18], "max"))
        _put("Forecast_APCP_Max_12h_Window_0to24h_mm", _nan_stat_no_warning([i00 + i06, i06 + i12, i12 + i18], "max"))

    return table


def add_forecast_hour_summary_features(table):
    """Add temporal Mean/Min/Max/Std summaries across RAP valid hours for every *_fhr_XXh predictor.

    Raw valid-time columns such as PWAT_fhr_00h, PWAT_fhr_06h, ..., are useful
    cache/debug fields but are not interpretable model predictors.  This function
    converts each forecast-hour family into a small, stable summary family such as:

        PWAT_0_6_12_18_24h_Mean
        PWAT_0_6_12_18_24h_Min
        PWAT_0_6_12_18_24h_Max
        PWAT_0_6_12_18_24h_Std

    The spatial-radius pass then converts these source summaries into final
    R75km Mean/Min/Max/Std model features.
    """
    hour_re = re.compile(r"^(?P<base>.+)_fhr_(?P<hour>00|06|12|18|24)h$")
    groups = {}
    for col in list(table.columns if isinstance(table, pd.DataFrame) else table.keys()):
        m = hour_re.match(str(col))
        if not m:
            continue
        # Do not summarize target/verification/leakage fields if old chunks contain any.
        # Do NOT call _is_non_predictor_column() here because that intentionally
        # marks raw *_fhr_XXh cache/debug fields as excluded from the final model.
        # Those raw fields are exactly what this function must summarize first.
        cstr = str(col)
        if cstr in {"Date", "Lat", "Lon", "Year", TARGET_COLUMN, TRAIN_TARGET_COLUMN, R40KM_FRACTION_COLUMN, R40KM_TARGET_COUNT_COLUMN, R40KM_TARGET_EVENT_COUNT_COLUMN}:
            continue
        if any(cstr.startswith(prefix) for prefix in HYDRO_TARGET_PREFIXES):
            continue
        groups.setdefault(m.group("base"), []).append((int(m.group("hour")), col))

    if not groups:
        return table

    def _arr(col):
        return np.asarray(table[col], dtype=np.float32)

    def _put(col, vals):
        vals = np.asarray(vals, dtype=np.float32)
        if isinstance(table, pd.DataFrame):
            table[col] = vals
        else:
            table[col] = vals

    for base, hour_cols in groups.items():
        hour_cols = sorted(hour_cols, key=lambda x: x[0])
        cols = [c for _, c in hour_cols]
        arrs = [_arr(c) for c in cols]
        hour_tag = "_".join(str(h) for h, _ in hour_cols)
        out_prefix = f"{base}_{hour_tag}h"
        for stat_name, stat in [("Mean", "mean"), ("Min", "min"), ("Max", "max"), ("Std", "std")]:
            vals = _nan_stat_no_warning(arrs, stat)
            if vals is not None:
                _put(f"{out_prefix}_{stat_name}", vals)

    return table


def add_apcp_to_guidance_ffg_ratio_features(table):
    """Add duration-matched forecast APCP / guidance FFG ratio predictors.

    Deprecated mismatched predictors such as 24h APCP / 3h FFG are intentionally
    not created here.  The desired predictors are 6h QPF / 6h FFG, 12h QPF / 12h
    FFG, and 24h QPF / 24h FFG, plus summary stats across those ratios.
    """
    if not (USE_GUIDANCE_FFG_FEATURES and GUIDANCE_FFG_ADD_APCP_RATIOS):
        return table

    add_period_summary_features(table)

    def _has(col):
        return col in table

    def _arr(col):
        return np.asarray(table[col], dtype=np.float32)

    def _put(col, vals):
        vals = np.asarray(vals, dtype=np.float32)
        if isinstance(table, pd.DataFrame):
            table[col] = vals
        else:
            table[col] = vals

    # Duration-matched ratios.
    ratio_cols = []
    pairs = [
        ("Forecast_APCP_Max_6h_Window_0to24h_mm", "Guide_FFG_06h_mm", "Forecast_APCP_Max_6h_Window_0to24h_to_Guidance_FFG_06h_Ratio"),
        ("Forecast_APCP_Max_12h_Window_0to24h_mm", "Guide_FFG_12h_mm", "Forecast_APCP_Max_12h_Window_0to24h_to_Guidance_FFG_12h_Ratio"),
        ("APCP_RunTotal_0_24h", "Guide_FFG_24h_mm", "Forecast_APCP_24h_Total_to_Guidance_FFG_24h_Ratio"),
    ]
    for apcp_col, ffg_col, out_col in pairs:
        if _has(apcp_col) and _has(ffg_col):
            vals = _arr(apcp_col) / np.maximum(_arr(ffg_col), np.float32(0.01))
            _put(out_col, vals)
            ratio_cols.append(out_col)

    if ratio_cols:
        arrs = [_arr(c) for c in ratio_cols]
        for stat_name, stat in [("Mean", "mean"), ("Min", "min"), ("Max", "max"), ("Std", "std")]:
            vals = _nan_stat_no_warning(arrs, stat)
            if vals is not None:
                _put(f"Forecast_APCP_to_Guidance_FFG_Ratio_Across_6h12h24h_{stat_name}", vals)

    return table


def _is_deprecated_or_raw_period_predictor(col):
    """Raw period-specific fields kept in caches but excluded from fitting."""
    if not DROP_RAW_PERIOD_FEATURES_FROM_MODEL:
        return False
    c = str(col)
    deprecated_exact = {
        "APCP_RunTotal_0_24h_to_Guide_FFG_01h_Ratio",
        "APCP_RunTotal_0_24h_to_Guide_FFG_03h_Ratio",
        "APCP_RunTotal_0_24h_to_Guide_FFG_06h_Ratio",
        "APCP_RunTotal_0_24h_to_Guide_FFG_MinRatio",
        "Guide_FFG_06h_to_01h_Ratio",
        "Guide_FFG_Min_1_3_6h_mm",
        "Guide_FFG_Max_1_3_6h_mm",
    }
    if c in deprecated_exact:
        return True
    # Replace raw period fields with summary/smoothed versions.
    if re.fullmatch(r"APCP_RunTotal_0_(06|12|18|24)h", c):
        return True
    if re.fullmatch(r"APCP_Interval_(00_06|06_12|12_18|18_24)h", c):
        return True
    if re.fullmatch(r"Guide_FFG_(01|03|06|12|24)h_mm", c):
        return True
    # All raw RAP valid-time fields are cache/debug columns only. The model uses
    # temporal summaries across valid hours, then R75km neighborhood stats.
    if re.fullmatch(r".+_fhr_(00|06|12|18|24)h", c):
        return True
    return False



def add_missing_guidance_ffg_durations_to_frame(frame, label="frame"):
    """Ensure 12h/24h guidance FFG predictor columns exist even when reusing older chunks.

    Older cached chunks only contain 1/3/6h FFG.  This function samples the latest
    at/before-init FFG file by date onto the existing native RAP rows and adds any
    missing Guide_FFG_{duration}h_mm columns.  It is predictor-only and does not alter targets.
    """
    if not USE_GUIDANCE_FFG_FEATURES:
        return frame
    if not isinstance(frame, pd.DataFrame) or frame.empty:
        return frame
    if "Date" not in frame.columns or "Lat" not in frame.columns or "Lon" not in frame.columns:
        return frame
    missing_any = [f"Guide_FFG_{int(d):02d}h_mm" for d in GUIDANCE_FFG_DURATIONS_H if f"Guide_FFG_{int(d):02d}h_mm" not in frame.columns]
    if not missing_any:
        return frame
    print(f"Adding missing guidance FFG durations to {label}: {missing_any}")
    out = frame.copy()
    # Precreate as NaN to preserve order and allow partial filling by date.
    for c in missing_any:
        if c not in out.columns:
            out[c] = np.nan
    for date_value, idx in out.groupby(out["Date"].astype(str), sort=False).groups.items():
        idx_list = list(idx)
        sub = out.loc[idx_list]
        guide = build_guidance_ffg_predictors(
            date_str=str(date_value),
            lats_1d=pd.to_numeric(sub["Lat"], errors="coerce").to_numpy(dtype=np.float32),
            lons_1d=pd.to_numeric(sub["Lon"], errors="coerce").to_numpy(dtype=np.float32),
        )
        for col, vals in guide.items():
            if col not in out.columns:
                out[col] = np.nan
            out.loc[idx_list, col] = np.asarray(vals, dtype=np.float32)
    return out

def add_previous_24h_ffg_exceedance_features(frame):
    """Add prior-case/day FFG exceedance features by matching same grid point one day earlier."""
    if not USE_PREV24H_FFG_EXCEEDANCE_FEATURES:
        return frame
    if not isinstance(frame, pd.DataFrame) or frame.empty:
        return frame
    if TARGET_COLUMN not in frame.columns or "Date" not in frame.columns or "Lat" not in frame.columns or "Lon" not in frame.columns:
        return frame

    out = frame.copy()
    dates = pd.to_datetime(out["Date"].astype(str), format="%Y%m%d", errors="coerce")
    out["__DateKey"] = dates.dt.strftime("%Y%m%d")
    out["__PrevDateKey"] = (dates - pd.Timedelta(days=1)).dt.strftime("%Y%m%d")
    out["__LatKey"] = pd.to_numeric(out["Lat"], errors="coerce").round(4)
    out["__LonKey"] = pd.to_numeric(out["Lon"], errors="coerce").round(4)

    prev_cols = ["__DateKey", "__LatKey", "__LonKey", TARGET_COLUMN]
    rename = {TARGET_COLUMN: "PrevDay_MRMS_FFG_Exceeded_Point"}
    for c in [R40KM_FRACTION_COLUMN, R40KM_TARGET_EVENT_COUNT_COLUMN, R40KM_TARGET_COUNT_COLUMN]:
        if c in out.columns:
            prev_cols.append(c)
    prev = out[prev_cols].copy().rename(columns=rename)
    if R40KM_FRACTION_COLUMN in prev.columns:
        prev = prev.rename(columns={R40KM_FRACTION_COLUMN: "PrevDay_MRMS_FFG_Exceeded_R75km_Fraction"})
    if R40KM_TARGET_EVENT_COUNT_COLUMN in prev.columns:
        prev = prev.rename(columns={R40KM_TARGET_EVENT_COUNT_COLUMN: "PrevDay_MRMS_FFG_Exceeded_R75km_EventCount"})
    if R40KM_TARGET_COUNT_COLUMN in prev.columns:
        prev = prev.rename(columns={R40KM_TARGET_COUNT_COLUMN: "PrevDay_MRMS_FFG_Exceeded_R75km_NeighborCount"})

    out = out.merge(
        prev,
        how="left",
        left_on=["__PrevDateKey", "__LatKey", "__LonKey"],
        right_on=["__DateKey", "__LatKey", "__LonKey"],
        suffixes=("", "__prev"),
    )
    out["PrevDay_MRMS_FFG_Available"] = out["PrevDay_MRMS_FFG_Exceeded_Point"].notna().astype(np.float32)
    for c in [
        "PrevDay_MRMS_FFG_Exceeded_Point", "PrevDay_MRMS_FFG_Exceeded_R75km_Fraction", "PrevDay_MRMS_FFG_Exceeded_R75km_EventCount", "PrevDay_MRMS_FFG_Exceeded_R75km_NeighborCount"
    ]:
        if c in out.columns:
            out[c] = pd.to_numeric(out[c], errors="coerce").fillna(0).astype(np.float32)
    # Drop only temporary merge/key columns.  Preserve __Split when the caller
    # concatenates train/test before feature engineering and uses __Split to
    # separate them again afterward.
    drop = [c for c in out.columns if c.startswith("__") and c != "__Split"]
    out = out.drop(columns=drop, errors="ignore")
    return out


def _r40_smooth_numeric_features_for_one_date(sub, feature_cols, radius_km=R40KM_FEATURE_SMOOTH_RADIUS_KM):
    if not len(sub) or not feature_cols:
        return pd.DataFrame(index=sub.index)
    lat = pd.to_numeric(sub["Lat"], errors="coerce").to_numpy(dtype=float)
    lon = pd.to_numeric(sub["Lon"], errors="coerce").to_numpy(dtype=float)
    ok = np.isfinite(lat) & np.isfinite(lon)
    if not ok.any():
        return pd.DataFrame(index=sub.index)

    ok_pos = np.where(ok)[0]
    xyz = _latlon_to_unit_xyz_for_r75km(lat[ok], lon[ok])
    tree = cKDTree(xyz)
    chord_radius = 2.0 * np.sin((float(radius_km) / 6371.0) / 2.0)
    neigh_lists = tree.query_ball_point(xyz, r=chord_radius)

    # Build all new columns in a dictionary and create one DataFrame at the end.
    # This avoids pandas DataFrame fragmentation from repeated out[col] = arr.
    out_cols = {}
    for col in feature_cols:
        vals_all = pd.to_numeric(sub[col], errors="coerce").to_numpy(dtype=np.float32)
        vals_ok = vals_all[ok]
        stat_arrays = {stat: np.full(len(sub), np.nan, dtype=np.float32) for stat in R40KM_FEATURE_SMOOTH_STATS}
        for local_i, neigh in enumerate(neigh_lists):
            if not neigh:
                continue
            vv = vals_ok[np.asarray(neigh, dtype=int)]
            good = np.isfinite(vv)
            if not good.any():
                continue
            vv = vv[good]
            global_pos = ok_pos[local_i]
            if "Mean" in stat_arrays:
                stat_arrays["Mean"][global_pos] = np.float32(np.mean(vv))
            if "Min" in stat_arrays:
                stat_arrays["Min"][global_pos] = np.float32(np.min(vv))
            if "Max" in stat_arrays:
                stat_arrays["Max"][global_pos] = np.float32(np.max(vv))
            if "Std" in stat_arrays:
                stat_arrays["Std"][global_pos] = np.float32(np.std(vv))
        for stat, arr in stat_arrays.items():
            out_cols[f"{col}_R75km_{stat}"] = arr
    return pd.DataFrame(out_cols, index=sub.index)

def _chunks_list(seq, n):
    n = max(1, int(n))
    for i in range(0, len(seq), n):
        yield seq[i:i+n]


def add_r75km_smoothed_feature_stats(frame, candidate_cols=None, label="frame"):
    """Add 75-km neighborhood summary fields on native grid; does not regrid/coarsen.

    Memory-safe version:
      * processes base columns in small blocks
      * processes one date at a time
      * concatenates each block once
      * prints/tqdm progress for date and column-block loops

    This avoids the large temporary smooth_all dataframe that was causing OOM kills.
    """
    if not USE_R40KM_SMOOTHED_FEATURES:
        return frame
    if not isinstance(frame, pd.DataFrame) or frame.empty:
        return frame
    if "Date" not in frame.columns or "Lat" not in frame.columns or "Lon" not in frame.columns:
        return frame

    if candidate_cols is None:
        candidate_cols = [c for c in frame.columns if _should_r40_smooth_feature(c)]

    suffixes = tuple(f"_R75km_{s}" for s in R40KM_FEATURE_SMOOTH_STATS)
    candidate_cols = [c for c in candidate_cols if c in frame.columns and not str(c).endswith(suffixes)]

    # Avoid duplicate columns if daily chunks already contain smoothed versions and the
    # master-level pass is only ensuring feature completeness.
    candidate_cols = [
        c for c in candidate_cols
        if not all(f"{c}_R75km_{s}" in frame.columns for s in R40KM_FEATURE_SMOOTH_STATS)
    ]
    if not candidate_cols:
        print(f"75-km smoothed feature stats for {label}: all requested columns already present; skipping.")
        return frame

    # Pre-compute group indices once.  Keep order stable.
    date_groups = list(frame.groupby(frame["Date"].astype(str), sort=False).groups.items())
    n_dates = len(date_groups)
    block_size = max(1, int(globals().get("R40KM_SMOOTH_BASE_COL_BLOCK_SIZE", 4)))
    col_blocks = list(_chunks_list(candidate_cols, block_size))

    print(
        f"Adding 75-km smoothed feature stats to {label}: "
        f"{len(candidate_cols)} base columns, {len(R40KM_FEATURE_SMOOTH_STATS)} stats, "
        f"{n_dates} dates, block_size={block_size}, blocks={len(col_blocks)}"
    )

    out = frame

    for ib, block in enumerate(tqdm(col_blocks, desc=f"R100 smooth col-blocks [{label}]", unit="block"), start=1):
        print(f"  R100 smooth {label}: block {ib}/{len(col_blocks)} with {len(block)} columns: {block}", flush=True)
        parts = []

        iterator = tqdm(date_groups, desc=f"R100 smooth dates [{label} block {ib}/{len(col_blocks)}]", unit="date", leave=False)
        for date_value, idx_labels in iterator:
            sub = out.loc[list(idx_labels), ["Date", "Lat", "Lon"] + list(block)].copy()
            smooth = _r40_smooth_numeric_features_for_one_date(sub, list(block))
            parts.append(smooth)

        if parts:
            smooth_block = pd.concat(parts, axis=0).reindex(out.index)
            # Force float32 to reduce memory.
            for c in smooth_block.columns:
                smooth_block[c] = pd.to_numeric(smooth_block[c], errors="coerce").astype(np.float32)
            out = pd.concat([out, smooth_block], axis=1, copy=False)
            del smooth_block
        del parts
        gc.collect()

    # One copy at the end de-fragments the frame after all concat blocks.
    return out.copy()


def _should_r40_smooth_feature(col):
    c = str(col)
    if _is_non_predictor_column(c) or _is_deprecated_or_raw_period_predictor(c):
        return False
    if c.endswith(tuple(f"_R75km_{s}" for s in R40KM_FEATURE_SMOOTH_STATS)):
        return False
    # Smooth the engineered hydrologic/precipitation summary fields and prior-day
    # exceedance proxies.  This extends the local signal to nearby grid points without
    # changing the native 13-km grid.\n
    tokens = [
        "Forecast_APCP_RunningTotals_0to6_0to12_0to18_0to24h_mm_",
        "Forecast_APCP_6hIntervals_0to24h_mm_",
        "Guidance_FFG_1h3h6h12h24h_mm_",
        "Forecast_APCP_Max_6h_Window_0to24h_mm",
        "Forecast_APCP_Max_12h_Window_0to24h_mm",
        "Forecast_APCP_Max_6h_Window_0to24h_to_Guidance_FFG_06h_Ratio",
        "Forecast_APCP_Max_12h_Window_0to24h_to_Guidance_FFG_12h_Ratio",
        "Forecast_APCP_24h_Total_to_Guidance_FFG_24h_Ratio",
        "Forecast_APCP_to_Guidance_FFG_Ratio_Across_6h12h24h_",
        "PrevDay_MRMS_FFG_",
    ]
    if any(t in c for t in tokens):
        return True
    # General RAP valid-time summaries created by add_forecast_hour_summary_features().
    # Examples: PWAT_0_6_12_18_24h_Mean, MLCAPE_0_6_12_18_24h_Max.
    if re.search(r"_0_6_12_18_24h_(Mean|Min|Max|Std)$", c):
        return True
    return False


def apply_v28_hydro_feature_engineering(frame, label="frame", add_prev24=False, do_r40_smooth=True):
    """Idempotently add v28 hydrologic summary, prior-day, and optionally 75-km smoothed features."""
    if not isinstance(frame, pd.DataFrame) or frame.empty:
        return frame
    out = frame.copy()
    out = add_missing_guidance_ffg_durations_to_frame(out, label=label)
    add_period_summary_features(out)
    add_forecast_hour_summary_features(out)
    add_apcp_to_guidance_ffg_ratio_features(out)
    if add_prev24:
        out = add_previous_24h_ffg_exceedance_features(out)
    if do_r40_smooth:
        out = add_r75km_smoothed_feature_stats(out, label=label)
    return out


def _radius_feature_suffix_regex():
    radius = int(round(float(globals().get("R40KM_FEATURE_SMOOTH_RADIUS_KM", 100.0))))
    stats = "|".join(map(re.escape, R40KM_FEATURE_SMOOTH_STATS))
    return rf"_R{radius}km_({stats})$"


def _is_radius_smoothed_stat_feature(col):
    return re.search(_radius_feature_suffix_regex(), str(col)) is not None


def _is_excluded_from_model_feature_column(col):
    """Return True for columns that must not enter X.

    v28 intentionally makes the fitted model use only R75km neighborhood
    Mean/Min/Max/Std features.  Raw fields remain in caches for diagnostics and
    for rebuilding the R75km stats, but they are excluded from feature_names.json.
    """
    c = str(col)
    if _is_non_predictor_column(c):
        return True
    if _is_deprecated_or_raw_period_predictor(c):
        return True
    if USE_RADIUS_ONLY_MODEL_FEATURES and not _is_radius_smoothed_stat_feature(c):
        return True
    return False


def describe_model_feature_name(feature_name):
    """Human-readable description for viewer/SHAP feature dictionaries."""
    name = str(feature_name)
    m = re.search(r"_R(?P<radius>\d+)km_(?P<stat>Mean|Min|Max|Std)$", name)
    radius_txt = f"{m.group('radius')} km" if m else f"{int(R40KM_FEATURE_SMOOTH_RADIUS_KM)} km"
    stat_txt = m.group("stat") if m else "value"
    base = re.sub(r"_R\d+km_(Mean|Min|Max|Std)$", "", name)

    known = {
        "PrevDay_MRMS_FFG_Exceeded_Point": "previous day's point MRMS QPE exceedance of flash flood guidance",
        "PrevDay_MRMS_FFG_Exceeded_R75km_Fraction": "previous day's fraction of grid points within 75 km with MRMS QPE exceeding FFG",
        "PrevDay_MRMS_FFG_Exceeded_R75km_EventCount": "previous day's count of grid points within 75 km with MRMS QPE exceeding FFG",
        "PrevDay_MRMS_FFG_Exceeded_R75km_NeighborCount": "number of valid previous-day grid points within 75 km",
        "PrevDay_MRMS_FFG_Available": "indicator that previous-day MRMS/FFG data were available for the same grid point",
        "Forecast_APCP_Max_6h_Window_0to24h_to_Guidance_FFG_06h_Ratio": "maximum forecast 6-hour precipitation divided by 6-hour guidance FFG",
        "Forecast_APCP_Max_12h_Window_0to24h_to_Guidance_FFG_12h_Ratio": "maximum forecast 12-hour precipitation divided by 12-hour guidance FFG",
        "Forecast_APCP_24h_Total_to_Guidance_FFG_24h_Ratio": "forecast 24-hour total precipitation divided by 24-hour guidance FFG",
        "Forecast_APCP_to_Guidance_FFG_Ratio_Across_6h12h24h_Mean": "mean of 6h, 12h, and 24h forecast-precipitation/guidance-FFG ratios",
        "Forecast_APCP_to_Guidance_FFG_Ratio_Across_6h12h24h_Min": "minimum of 6h, 12h, and 24h forecast-precipitation/guidance-FFG ratios",
        "Forecast_APCP_to_Guidance_FFG_Ratio_Across_6h12h24h_Max": "maximum of 6h, 12h, and 24h forecast-precipitation/guidance-FFG ratios",
        "Forecast_APCP_to_Guidance_FFG_Ratio_Across_6h12h24h_Std": "standard deviation of 6h, 12h, and 24h forecast-precipitation/guidance-FFG ratios",
    }
    base_desc = known.get(base)
    if base_desc is None:
        base_desc = base.replace("_", " ")
        base_desc = base_desc.replace("0 6 12 18 24h", "across 0, 6, 12, 18, and 24 forecast hours")
    return f"{stat_txt} within {radius_txt} of {base_desc}"


def fetch_mrms_ffg_exceedance_target(date_str, lats_1d, lons_1d):
    """
    Build observed FFG-exceedance target for a 12z-to-12z case.

    Uses hourly observed MRMS QPE ending at 13z..12z next day.  For each 1h/3h/6h rolling
    observed accumulation, it compares QPE against the latest FFG file at or before the
    start of that accumulation window.  Target is positive if any duration/window exceeds FFG.
    """
    base_dt = datetime.strptime(str(date_str), "%Y%m%d") + timedelta(hours=int(TARGET_VALID_START_HOUR))
    n = len(lats_1d)

    qpe_1h = {}
    mrms_lats = mrms_lons = None
    missing_mrms = []

    for end_offset in range(1, int(TARGET_VALID_WINDOW_HOURS) + 1):
        end_dt = base_dt + timedelta(hours=end_offset)
        path = ensure_mrms_qpe_1h_file(end_dt)
        if path is None:
            missing_mrms.append(end_dt.strftime("%Y%m%d%H"))
            if REQUIRE_ALL_MRMS_QPE_HOURS:
                try:
                    pd.DataFrame({"missing_mrms_hour": missing_mrms}).to_csv(
                        os.path.join(HYDRO_TARGET_DEBUG_DIR, f"missing_mrms_{date_str}.csv"),
                        index=False,
                    )
                except Exception:
                    pass
                return None
            continue

        try:
            if mrms_lats is None:
                grid, mrms_lats, mrms_lons = _read_grib_grid(path, include_latlon=True)
            else:
                grid = _read_grib_grid(path, include_latlon=False)
            grid = np.where(np.isfinite(grid), grid, np.nan).astype(np.float32)
            grid = np.where(grid < 0.0, 0.0, grid).astype(np.float32)
            sampled = _sample_grid_to_domain(
                grid=grid,
                src_lats=mrms_lats,
                src_lons=mrms_lons,
                target_lats_1d=lats_1d,
                target_lons_1d=lons_1d,
                cache_key="mrms_qpe_1h",
            )
            qpe_1h[end_offset] = sampled
        except Exception as e:
            missing_mrms.append(f"{end_dt.strftime('%Y%m%d%H')}:{repr(e)}")
            if REQUIRE_ALL_MRMS_QPE_HOURS:
                try:
                    pd.DataFrame({"missing_mrms_hour": missing_mrms}).to_csv(
                        os.path.join(HYDRO_TARGET_DEBUG_DIR, f"missing_mrms_{date_str}.csv"),
                        index=False,
                    )
                except Exception:
                    pass
                return None

    if missing_mrms and REQUIRE_ALL_MRMS_QPE_HOURS:
        try:
            pd.DataFrame({"missing_mrms_hour": missing_mrms}).to_csv(
                os.path.join(HYDRO_TARGET_DEBUG_DIR, f"missing_mrms_{date_str}.csv"),
                index=False,
            )
        except Exception:
            pass
        return None

    if not qpe_1h:
        return None

    out = {
        TARGET_COLUMN: np.zeros(n, dtype=np.int8),
        "Obs_FFG_NumDurationsExceeded": np.zeros(n, dtype=np.int8),
    }

    duration_exceeded_any = []

    for duration_h in TARGET_DURATIONS_H:
        cols = _ffg_duration_columns(duration_h)
        target_arr = np.zeros(n, dtype=np.int8)
        max_ratio = np.full(n, np.nan, dtype=np.float32)
        max_qpe = np.full(n, np.nan, dtype=np.float32)
        ffg_at_max = np.full(n, np.nan, dtype=np.float32)
        valid_windows = np.zeros(n, dtype=np.int16)

        for end_offset in range(int(duration_h), int(TARGET_VALID_WINDOW_HOURS) + 1):
            needed = list(range(end_offset - int(duration_h) + 1, end_offset + 1))
            if any(k not in qpe_1h for k in needed):
                continue

            qpe_sum = np.sum(np.stack([qpe_1h[k] for k in needed], axis=0), axis=0).astype(np.float32)
            window_start_dt = base_dt + timedelta(hours=end_offset - int(duration_h))
            ffg_path = ensure_ffg_file_at_or_before(window_start_dt)

            if ffg_path is None:
                if REQUIRE_FFG_FOR_TARGET:
                    continue
                else:
                    continue

            ffg = _get_ffg_sampled(ffg_path, int(duration_h), lats_1d, lons_1d)
            if ffg is None:
                continue

            valid = np.isfinite(qpe_sum) & np.isfinite(ffg) & (ffg >= float(MIN_VALID_FFG_MM))
            if not valid.any():
                continue

            ratio = np.full(n, np.nan, dtype=np.float32)
            ratio[valid] = (qpe_sum[valid] / ffg[valid]).astype(np.float32)
            valid_windows[valid] += 1

            exceeded = valid & (ratio >= float(TARGET_RATIO_THRESHOLD))
            target_arr[exceeded] = 1

            update = valid & (~np.isfinite(max_ratio) | (ratio > max_ratio))
            max_ratio[update] = ratio[update]
            max_qpe[update] = qpe_sum[update]
            ffg_at_max[update] = ffg[update]

        out[cols["target"]] = target_arr.astype(np.int8)
        out[cols["max_qpe"]] = max_qpe.astype(np.float32)
        out[cols["ffg_at_max"]] = ffg_at_max.astype(np.float32)
        out[cols["max_ratio"]] = max_ratio.astype(np.float32)
        out[cols["valid_windows"]] = valid_windows.astype(np.int16)
        duration_exceeded_any.append(target_arr.astype(bool))

    if duration_exceeded_any:
        stack = np.stack(duration_exceeded_any, axis=0)
        out[TARGET_COLUMN] = np.any(stack, axis=0).astype(np.int8)
        out["Obs_FFG_NumDurationsExceeded"] = np.sum(stack, axis=0).astype(np.int8)
    else:
        return None

    # Debug summary per date.
    try:
        rows = []
        for key, arr in out.items():
            a = np.asarray(arr)
            finite = np.isfinite(a.astype(float)) if a.size else np.array([], dtype=bool)
            rows.append({
                "date": date_str,
                "column": key,
                "n": int(a.size),
                "finite": int(finite.sum()) if finite.size else 0,
                "mean": float(np.nanmean(a.astype(float))) if finite.any() else np.nan,
                "max": float(np.nanmax(a.astype(float))) if finite.any() else np.nan,
            })
        pd.DataFrame(rows).to_csv(
            os.path.join(HYDRO_TARGET_DEBUG_DIR, f"hydro_target_summary_{date_str}.csv"),
            index=False,
        )
    except Exception:
        pass

    return out

def _empty_feature(num_pixels, dtype=np.float32):
    return np.full(num_pixels, np.nan, dtype=dtype)


def _safe_speed(u, v):
    if u is None or v is None:
        return None
    return np.sqrt((u.astype(np.float32) ** 2) + (v.astype(np.float32) ** 2))


def _safe_shear(u1, v1, u2, v2):
    if u1 is None or v1 is None or u2 is None or v2 is None:
        return None
    return np.sqrt(((u2 - u1).astype(np.float32) ** 2) + ((v2 - v1).astype(np.float32) ** 2))


def _safe_mean_wind_speed(u1, v1, u2, v2):
    if u1 is None or v1 is None or u2 is None or v2 is None:
        return None
    mean_u = 0.5 * (u1 + u2)
    mean_v = 0.5 * (v1 + v2)
    return np.sqrt((mean_u.astype(np.float32) ** 2) + (mean_v.astype(np.float32) ** 2))


def _take_along_level(stack, idx):
    """
    stack shape: (n_levels, ny, nx)
    idx shape:   (ny, nx)
    returns:     (ny, nx)
    """
    return np.take_along_axis(stack, idx[None, :, :], axis=0)[0]


def _nearest_profile_value(profile, target_height_m, field_name):
    """
    Return the field value from the pressure level closest to target_height_m AGL at each grid point.
    profile is a list of dicts with z_agl, u, v, t.
    """
    valid = [p for p in profile if p.get("z_agl") is not None and p.get(field_name) is not None]
    if not valid:
        return None

    z_stack = np.stack([p["z_agl"].astype(np.float32) for p in valid], axis=0)
    f_stack = np.stack([p[field_name].astype(np.float32) for p in valid], axis=0)

    dist = np.abs(z_stack - float(target_height_m))
    idx = np.nanargmin(dist, axis=0)

    return _take_along_level(f_stack, idx).astype(np.float32)


def _mean_wind_speed_between_heights(profile, lower_m, upper_m, include_10m_uv=None):
    """
    Approximate layer mean wind speed using all available pressure levels whose AGL height falls
    inside [lower_m, upper_m]. Optionally include 10m wind in the layer.
    """
    u_list = []
    v_list = []

    if include_10m_uv is not None and lower_m <= 10.0 <= upper_m:
        u10, v10 = include_10m_uv
        if u10 is not None and v10 is not None:
            u_list.append(u10.astype(np.float32))
            v_list.append(v10.astype(np.float32))

    for p in profile:
        z = p.get("z_agl")
        u = p.get("u")
        v = p.get("v")

        if z is None or u is None or v is None:
            continue

        mask = (z >= float(lower_m)) & (z <= float(upper_m))
        u_list.append(np.where(mask, u, np.nan).astype(np.float32))
        v_list.append(np.where(mask, v, np.nan).astype(np.float32))

    if not u_list:
        return None

    with warnings.catch_warnings():
        warnings.simplefilter("ignore", category=RuntimeWarning)
        mean_u = np.nanmean(np.stack(u_list, axis=0), axis=0)
        mean_v = np.nanmean(np.stack(v_list, axis=0), axis=0)

    out = np.sqrt(mean_u**2 + mean_v**2).astype(np.float32)
    out[~np.isfinite(out)] = np.nan
    return out


def _bulk_shear_0_6km(profile, u10, v10):
    """
    Approximate 0-6 km bulk shear as the vector difference between 10m wind and the
    pressure-level wind closest to 6 km AGL.
    """
    u6 = _nearest_profile_value(profile, 6000.0, "u")
    v6 = _nearest_profile_value(profile, 6000.0, "v")

    if u10 is None or v10 is None or u6 is None or v6 is None:
        return None

    return _safe_shear(u10, v10, u6, v6)


def _max_deep_shear_0_1_to_6_10km(profile, u10, v10):
    """
    Approximate MMP very-deep shear:
    max vector shear using lower-bound winds from 0-1 km AGL and upper-bound winds from 6-10 km AGL.

    Exact SPC/NSSL MMP uses sounding levels. This uses available NAM pressure levels plus 10m wind.
    """
    lower_candidates = []
    upper_candidates = []

    if u10 is not None and v10 is not None:
        lower_candidates.append((u10.astype(np.float32), v10.astype(np.float32)))

    for p in profile:
        z = p.get("z_agl")
        u = p.get("u")
        v = p.get("v")

        if z is None or u is None or v is None:
            continue

        z_mean = float(np.nanmean(z))

        # Use level-wide average height to decide whether this pressure level is generally in the layer.
        # This keeps the computation tractable for CONUS-scale grids.
        if 0.0 <= z_mean <= 1000.0:
            lower_candidates.append((u.astype(np.float32), v.astype(np.float32)))
        elif 6000.0 <= z_mean <= 10000.0:
            upper_candidates.append((u.astype(np.float32), v.astype(np.float32)))

    if not lower_candidates or not upper_candidates:
        return None

    shear_list = []
    for ul, vl in lower_candidates:
        for uu, vu in upper_candidates:
            shear_list.append(np.sqrt((uu - ul)**2 + (vu - vl)**2).astype(np.float32))

    return np.nanmax(np.stack(shear_list, axis=0), axis=0).astype(np.float32)


def _lapse_rate_3_8km(profile):
    """
    Approximate 3-8 km lapse rate in K/km using nearest pressure-level temperatures.
    Positive values indicate temperature decreasing with height.
    """
    t3 = _nearest_profile_value(profile, 3000.0, "t")
    t8 = _nearest_profile_value(profile, 8000.0, "t")

    if t3 is None or t8 is None:
        return None

    # T is Kelvin; K/km == degC/km for a temperature difference.
    return ((t3 - t8) / 5.0).astype(np.float32)


def _derecho_composite_namcalc(dcape, mucape, shear06_ms, meanwind06_ms):
    """
    NAM-calculated Derecho Composite Parameter.

    DCP = (DCAPE/980) * (MUCAPE/2000) * (0-6 km shear/20 kt) * (0-6 km mean wind/16 kt)

    This is only as exact as the NAM ingredients available here. The 0-6 km shear and mean wind
    are approximated from 10m wind plus pressure-level winds/heights.
    """
    if dcape is None or mucape is None or shear06_ms is None or meanwind06_ms is None:
        return None

    return (
        (np.maximum(dcape, 0) / 980.0)
        * (np.maximum(mucape, 0) / 2000.0)
        * (np.maximum(shear06_ms, 0) / 10.28888)  # 20 kt in m/s
        * (np.maximum(meanwind06_ms, 0) / 8.23110)  # 16 kt in m/s
    ).astype(np.float32)


def _mmp_namcalc(max_shear_ms, lapse_3_8_km, mucape, meanwind_3_12_ms):
    """
    NAM-calculated approximation to the NSSL MCS Maintenance Probability.

    NSSL describes MMP as a logistic-regression probability using:
      - very-deep vertical wind shear
      - 3-8 km lapse rate
      - most-unstable CAPE
      - 3-12 km mean wind speed

    The NSSL page gives coefficients:
      a0 = 13.0
      a1 = -4.59e-2
      a2 = -1.16
      a3 = -6.17e-4
      a4 = -0.17

    Because the published equation is written with negative predictor coefficients,
    the probability is computed here as:
      MMP = 100 / (1 + exp(linear_term))

    MMP is zeroed where MUCAPE < 100 J/kg.
    """
    if max_shear_ms is None or lapse_3_8_km is None or mucape is None or meanwind_3_12_ms is None:
        return None

    linear_term = (
        13.0
        + (-4.59e-2 * max_shear_ms)
        + (-1.16 * lapse_3_8_km)
        + (-6.17e-4 * mucape)
        + (-0.17 * meanwind_3_12_ms)
    )

    linear_term = np.clip(linear_term, -80, 80)
    prob = 100.0 / (1.0 + np.exp(linear_term))
    prob = np.where(mucape < 100.0, 0.0, prob)

    return prob.astype(np.float32)




def _grib_key(grb, key, default=None):
    """
    pygrib exposes some keys as attributes and others only via item access.
    Try both.
    """
    try:
        val = getattr(grb, key)
        if val is not None:
            return val
    except Exception:
        pass

    try:
        val = grb[key]
        if val is not None:
            return val
    except Exception:
        pass

    return default


def _extract_ints_from_value(value):
    """
    Extract integer hour values from GRIB key strings such as:
      '0-3', '3-6', '0-3 hour acc fcst', 3
    """
    if value is None:
        return []

    if isinstance(value, (int, np.integer)):
        return [int(value)]

    if isinstance(value, float):
        if np.isfinite(value):
            return [int(value)]
        return []

    txt = str(value)
    vals = re.findall(r"-?\d+", txt)
    return [int(v) for v in vals]


def _parse_grib_step_window(grb, fallback_end=None):
    """
    Return (start_hour, end_hour) for an accumulated precipitation GRIB message.

    This version is intentionally defensive for NAM/NCEP GRIB2:
      - tries raw GRIB keys and pygrib attributes
      - handles stepRange like '0-3' and '3-6'
      - uses lengthOfTimeRange/statisticalProcessDuration if available
      - falls back to the forecast hour only as a last resort
    """
    start = _grib_key(grb, "startStep", None)
    end = _grib_key(grb, "endStep", None)

    start_vals = _extract_ints_from_value(start)
    end_vals = _extract_ints_from_value(end)

    if start_vals and end_vals:
        return int(start_vals[0]), int(end_vals[-1])

    step_range = _grib_key(grb, "stepRange", None)
    vals = _extract_ints_from_value(step_range)
    if len(vals) >= 2:
        return int(vals[0]), int(vals[1])
    if len(vals) == 1:
        end_hr = int(vals[0])
    else:
        end_hr = None

    if end_hr is None:
        for key in ["forecastTime", "forecastTimeInHours", "endStep"]:
            vals = _extract_ints_from_value(_grib_key(grb, key, None))
            if vals:
                end_hr = int(vals[-1])
                break

    if end_hr is None:
        end_hr = fallback_end

    if end_hr is None:
        return None, None

    length = None
    for key in [
        "lengthOfTimeRange",
        "lengthOfTimeRangeOfStatisticalProcess",
        "statisticalProcessDuration",
    ]:
        vals = _extract_ints_from_value(_grib_key(grb, key, None))
        if vals:
            length = int(vals[-1])
            break

    if length is not None and length > 0 and length <= 240:
        start_hr = max(0, int(end_hr) - int(length))
    else:
        start_hr = 0

    return int(start_hr), int(end_hr)


def _is_precip_accum_message(grb):
    """
    Robustly identify total accumulated precipitation messages.

    NAM/NCEP files can expose APCP as:
      shortName='tp'
      shortName='APCP'
      name='Total Precipitation'
      parameterName='Total precipitation'
      GRIB2 discipline=0, parameterCategory=1, parameterNumber=8
    """
    text_parts = []
    for key in [
        "shortName",
        "name",
        "parameterName",
        "cfName",
        "cfVarName",
        "marsParam",
        "parameterUnits",
    ]:
        val = _grib_key(grb, key, "")
        text_parts.append(str(val))

    joined = " ".join(text_parts).upper()
    compact = joined.replace("_", " ").replace("-", " ")
    short = str(_grib_key(grb, "shortName", "")).upper().strip()

    if short in {"APCP", "TP", "TOTPREC"}:
        return True

    if "TOTAL PRECIPITATION" in compact:
        return True

    if "PRECIPITATION" in compact and ("ACCUM" in compact or "TOTAL" in compact):
        return True

    try:
        discipline = int(_grib_key(grb, "discipline", -999))
        category = int(_grib_key(grb, "parameterCategory", -999))
        number = int(_grib_key(grb, "parameterNumber", -999))
        if discipline == 0 and category == 1 and number == 8:
            return True
    except Exception:
        pass

    return False


def _apcp_values_to_array(values):
    """
    Convert pygrib values, including masked arrays, to float32.
    """
    try:
        if hasattr(values, "filled"):
            arr = values.filled(np.nan)
        else:
            arr = values
        return np.asarray(arr, dtype=np.float32)
    except Exception:
        return None


def _write_apcp_debug(date_str, fhr, filepath, debug_rows):
    if not APCP_DEBUG or not debug_rows:
        return

    try:
        os.makedirs(APCP_DEBUG_DIR, exist_ok=True)
        out_path = os.path.join(APCP_DEBUG_DIR, f"apcp_messages_{date_str}_f{fhr:02d}.csv")
        pd.DataFrame(debug_rows).to_csv(out_path, index=False)
    except Exception:
        pass


def extract_apcp_windows_from_grib(grbs, fallback_fhr, date_str=None, filepath=None):
    """
    Extract APCP/TP accumulation windows from an opened pygrib file.

    Returns:
      list of (start_hour, end_hour, grid)

    Also writes debug CSVs for early dates so we can verify what GRIB messages were seen.
    """
    windows = []
    debug_rows = []

    try:
        grbs.seek(0)
    except Exception:
        pass

    try:
        for msg_idx, grb in enumerate(grbs, start=1):
            is_precip = _is_precip_accum_message(grb)

            name = str(_grib_key(grb, "name", ""))
            short_name = str(_grib_key(grb, "shortName", ""))
            parameter_name = str(_grib_key(grb, "parameterName", ""))
            level_type = str(_grib_key(grb, "typeOfLevel", ""))
            level = _grib_key(grb, "level", None)

            precip_like_text = " ".join([name, short_name, parameter_name]).upper()
            precip_like = ("PRECIP" in precip_like_text) or short_name.upper() in {"APCP", "TP"}

            if not is_precip and not precip_like:
                continue

            start_hr, end_hr = _parse_grib_step_window(grb, fallback_end=fallback_fhr)

            row = {
                "date": date_str,
                "fhr_file": fallback_fhr,
                "filepath": filepath,
                "msg_idx": msg_idx,
                "accepted_as_apcp": bool(is_precip),
                "shortName": short_name,
                "name": name,
                "parameterName": parameter_name,
                "typeOfLevel": level_type,
                "level": level,
                "discipline": _grib_key(grb, "discipline", None),
                "parameterCategory": _grib_key(grb, "parameterCategory", None),
                "parameterNumber": _grib_key(grb, "parameterNumber", None),
                "forecastTime": _grib_key(grb, "forecastTime", None),
                "stepRange": _grib_key(grb, "stepRange", None),
                "startStep": _grib_key(grb, "startStep", None),
                "endStep": _grib_key(grb, "endStep", None),
                "stepType": _grib_key(grb, "stepType", None),
                "lengthOfTimeRange": _grib_key(grb, "lengthOfTimeRange", None),
                "lengthOfTimeRangeOfStatisticalProcess": _grib_key(grb, "lengthOfTimeRangeOfStatisticalProcess", None),
                "parsed_start": start_hr,
                "parsed_end": end_hr,
            }

            arr = None
            if is_precip:
                arr = _apcp_values_to_array(grb.values)

            if arr is not None and np.isfinite(arr).any():
                row["min"] = float(np.nanmin(arr))
                row["max"] = float(np.nanmax(arr))
                row["mean"] = float(np.nanmean(arr))
            else:
                row["min"] = np.nan
                row["max"] = np.nan
                row["mean"] = np.nan

            debug_rows.append(row)

            if not is_precip:
                continue

            if start_hr is None or end_hr is None:
                continue

            if end_hr < start_hr or end_hr < 0:
                continue

            if arr is None or not np.isfinite(arr).any():
                continue

            windows.append((int(start_hr), int(end_hr), arr.astype(np.float32, copy=False)))

    except Exception as e:
        debug_rows.append({
            "date": date_str,
            "fhr_file": fallback_fhr,
            "filepath": filepath,
            "error": repr(e),
        })

    try:
        grbs.seek(0)
    except Exception:
        pass

    write_debug = True
    if date_str is not None:
        try:
            existing_dates = set()
            if os.path.isdir(APCP_DEBUG_DIR):
                for p in glob.glob(os.path.join(APCP_DEBUG_DIR, "apcp_messages_*_f*.csv")):
                    base = os.path.basename(p)
                    parts = base.split("_")
                    if len(parts) >= 3:
                        existing_dates.add(parts[2])
            if len(existing_dates) >= APCP_DEBUG_MAX_DATES and str(date_str) not in existing_dates:
                write_debug = False
        except Exception:
            write_debug = True

    if write_debug:
        _write_apcp_debug(str(date_str), int(fallback_fhr), filepath, debug_rows)

    return windows


def _sum_apcp_intervals(interval_grids, end_fhr):

    """
    Sum direct consecutive interval fields to produce a 0-end_fhr running total.
    Returns None if any needed interval is unavailable.
    """
    needed_pairs = [(a, b) for a, b in APCP_INTERVAL_PAIRS if b <= end_fhr]
    grids = []
    for pair in needed_pairs:
        grid = interval_grids.get(pair)
        if grid is None:
            return None
        grids.append(grid)

    if not grids:
        return None

    return np.sum(np.stack(grids, axis=0), axis=0).astype(np.float32)


def prior_rap_feature_chunk_exists(date_str):
    """True when a previous v20-v23 daily RAP-feature parquet exists for this date."""
    for pth in _prior_rap_feature_chunk_candidates(date_str):
        try:
            if os.path.exists(pth) and os.path.getsize(pth) > 1024:
                return True, pth
        except Exception:
            continue
    return False, None


def _prior_rap_feature_chunk_candidates(date_str):
    """Prior daily RAP-feature chunks that can be reused for this v26 target experiment."""
    if not REUSE_PRIOR_RAP_FEATURE_CHUNKS:
        return []
    paths = []
    for d in PRIOR_RAP_FEATURE_CHUNK_DIRS:
        if not d:
            continue
        paths.append(os.path.join(d, f"pixel_features_{str(date_str)}.parquet"))
    return paths


def _row_indices_for_prior_feature_chunk(df_prior, lats_1d, lons_1d):
    """
    Map rows from a previous RAP-feature chunk back to the current 1-D domain arrays.

    Most chunks are in exactly the same Lat/Lon order as lats_1d/lons_1d.  If not, use a
    nearest-neighbor coordinate match with a tight tolerance.
    """
    if "Lat" not in df_prior.columns or "Lon" not in df_prior.columns:
        return None

    row_lats = df_prior["Lat"].to_numpy(dtype=np.float64)
    row_lons = df_prior["Lon"].to_numpy(dtype=np.float64)

    if len(row_lats) == len(lats_1d):
        try:
            same_order = (
                np.nanmax(np.abs(row_lats - np.asarray(lats_1d, dtype=np.float64))) <= PRIOR_RAP_FEATURE_COORD_TOL_DEG
                and np.nanmax(np.abs(row_lons - np.asarray(lons_1d, dtype=np.float64))) <= PRIOR_RAP_FEATURE_COORD_TOL_DEG
            )
            if same_order:
                return np.arange(len(lats_1d), dtype=np.int64)
        except Exception:
            pass

    tree = cKDTree(np.column_stack([np.asarray(lats_1d, dtype=np.float64), np.asarray(lons_1d, dtype=np.float64)]))
    dist, idx = tree.query(np.column_stack([row_lats, row_lons]), k=1)
    if len(dist) == 0 or not np.isfinite(dist).all():
        return None
    max_dist = float(np.nanmax(dist))
    if max_dist > float(PRIOR_RAP_FEATURE_COORD_TOL_DEG):
        tqdm.write(
            f"  prior RAP feature chunk coordinate mismatch: max nearest-neighbor distance={max_dist:.4f} deg"
        )
        return None
    return idx.astype(np.int64)


def build_daily_df_from_prior_rap_feature_chunk(date_str, domain_vars):
    """
    Reuse prior RAP forecast features and rebuild only v26 observed MRMS/FFG targets.

    This avoids redownloading/reopening RAP GRIBs when a previous v20-v23 run already produced
    the same daily forecast-feature parquet.  Observed MRMS/FFG/LSR columns from the old chunk
    are dropped so there is no target-definition contamination.
    """
    if not REUSE_PRIOR_RAP_FEATURE_CHUNKS:
        return None

    lats_2d, lons_2d, domain_mask, lats_1d, lons_1d = domain_vars

    for prior_path in _prior_rap_feature_chunk_candidates(date_str):
        if not os.path.exists(prior_path):
            continue

        try:
            df_prior = pd.read_parquet(prior_path)
        except Exception as e:
            tqdm.write(f"  could not read prior RAP feature chunk {prior_path}: {e}")
            continue

        if df_prior.empty or "Lat" not in df_prior.columns or "Lon" not in df_prior.columns:
            continue

        # v26f domain is a restricted subset of the older v20 RAP-feature chunks.
        # Filter the prior chunk first so coordinate matching stays one-to-one with the
        # current domain mask instead of failing because old rows outside the new domain remain.
        df_prior = filter_dataframe_to_training_domain(df_prior)
        if df_prior.empty:
            continue

        row_idx = _row_indices_for_prior_feature_chunk(df_prior, lats_1d, lons_1d)
        if row_idx is None:
            continue

        hydro_target = fetch_mrms_ffg_exceedance_target(
            date_str=date_str,
            lats_1d=lats_1d,
            lons_1d=lons_1d,
        )
        if hydro_target is None or TARGET_COLUMN not in hydro_target:
            tqdm.write(f"Skipping {date_str}: prior RAP features exist but MRMS/FFG target could not be built.")
            return None

        lsr_target_1d = fetch_iem_flash_flood_reports_pixel(
            date_str,
            lats_1d,
            lons_1d,
            domain_mask,
            lats_2d
        )

        # Drop all old target/observed verification columns before injecting the v26 target.
        drop_cols = []
        for c in df_prior.columns:
            if c in (TARGET_COLUMN, "Obs_LSR_FlashFlood_Report"):
                drop_cols.append(c)
            elif c.startswith("Target_") or c.startswith("Obs_"):
                drop_cols.append(c)
            elif any(str(c).startswith(prefix) for prefix in OBSERVED_LEAKAGE_PREFIXES):
                drop_cols.append(c)

        df = df_prior.drop(columns=sorted(set(drop_cols)), errors="ignore").copy()
        binary_target_full = np.asarray(hydro_target[TARGET_COLUMN], dtype=np.int8)
        frac_full, n_full, e_full = build_r75km_fractional_target_arrays(
            binary_target_full, lats_1d, lons_1d, radius_km=R40KM_TARGET_RADIUS_KM
        )

        df["Date"] = str(date_str)
        df[TARGET_COLUMN] = binary_target_full[row_idx].astype(np.int8)
        df[R40KM_FRACTION_COLUMN] = frac_full[row_idx].astype(np.float32)
        df[TRAIN_TARGET_COLUMN] = (e_full[row_idx] > 0).astype(np.int8)
        df[R40KM_TARGET_COUNT_COLUMN] = n_full[row_idx].astype(np.int16)
        df[R40KM_TARGET_EVENT_COUNT_COLUMN] = e_full[row_idx].astype(np.int16)
        df["Obs_LSR_FlashFlood_Report"] = np.asarray(lsr_target_1d, dtype=np.int8)[row_idx]

        for hydro_col, hydro_vals in hydro_target.items():
            if hydro_col == TARGET_COLUMN:
                continue
            df[hydro_col] = np.asarray(hydro_vals)[row_idx]

        # Add realtime-available FFG guidance predictors to reused RAP chunks.
        guide_features = build_guidance_ffg_predictors(
            date_str=date_str,
            lats_1d=lats_1d,
            lons_1d=lons_1d,
            row_idx=row_idx,
        )
        for guide_col, guide_vals in guide_features.items():
            df[guide_col] = guide_vals
        df = apply_v28_hydro_feature_engineering(df, label=f"daily {date_str} reused", add_prev24=False)

        # Keep Date/Lat/Lon/target columns near the front for readability.
        front = [c for c in ["Date", "Lat", "Lon", TARGET_COLUMN, TRAIN_TARGET_COLUMN, R40KM_FRACTION_COLUMN, R40KM_TARGET_COUNT_COLUMN, R40KM_TARGET_EVENT_COUNT_COLUMN, "Obs_LSR_FlashFlood_Report"] if c in df.columns]
        rest = [c for c in df.columns if c not in front]
        df = df[front + rest]

        tqdm.write(f"{date_str}: reused prior RAP feature chunk and rebuilt MRMS/FFG binary + R75km fractional targets: {prior_path}")
        return df

    return None


def process_daily_pixel_data(date_str, nam_dir, domain_vars, is_test_set=False):
    lats_2d, lons_2d, domain_mask, lats_1d, lons_1d = domain_vars

    reused_df = build_daily_df_from_prior_rap_feature_chunk(date_str, domain_vars)
    if reused_df is not None:
        return reused_df

    files_dict = download_nam_forecasts_osdf(date_str, nam_dir)

    missing_or_bad_fhrs = []
    for req_fhr in MIN_REQUIRED_FORECAST_HOURS:
        req_path = files_dict.get(f"fhr_{req_fhr:02d}h", "")
        if not validate_nam_forecast_file(req_path, date_str, req_fhr):
            missing_or_bad_fhrs.append(req_fhr)

    if missing_or_bad_fhrs:
        print(
            f"Skipping {date_str}: missing/invalid required RAP 09z catalog/AWS 6-hour valid-offset files "
            f"{missing_or_bad_fhrs}"
        )
        if REQUIRE_ALL_FORECAST_HOURS:
            return None

    if not validate_nam_forecast_file(files_dict.get("fhr_00h", ""), date_str, 0):
        return None

    lsr_target_1d = fetch_iem_flash_flood_reports_pixel(
        date_str,
        lats_1d,
        lons_1d,
        domain_mask,
        lats_2d
    )

    hydro_target = fetch_mrms_ffg_exceedance_target(
        date_str=date_str,
        lats_1d=lats_1d,
        lons_1d=lons_1d,
    )

    if hydro_target is None or TARGET_COLUMN not in hydro_target:
        print(f"Skipping {date_str}: unable to build observed MRMS QPE / FFG exceedance target.")
        return None

    target_1d = np.asarray(hydro_target[TARGET_COLUMN], dtype=np.int8)
    frac_target_1d, r40_neighbor_count_1d, r40_event_count_1d = build_r75km_fractional_target_arrays(
        target_1d, lats_1d, lons_1d, radius_km=R40KM_TARGET_RADIUS_KM
    )
    print(
        f"{date_str}: {R40KM_FRACTION_COLUMN} mean={float(np.nanmean(frac_target_1d)):.6f}, "
        f"any_event_rate={float(np.nanmean(r40_event_count_1d > 0)):.6f}, max_frac={float(np.nanmax(frac_target_1d)):.6f}, "
        f"mean_neighbors={float(np.nanmean(np.where(r40_neighbor_count_1d > 0, r40_neighbor_count_1d, np.nan))):.1f}"
    )

    # Exclude water pixels using NAM LAND mask from the f00 file.
    # LAND is usually 1 over land and 0 over water.
    land_keep_mask_1d = np.ones(len(lats_1d), dtype=bool)

    if EXCLUDE_WATER_PIXELS:
        try:
            f00_path = files_dict.get("fhr_00h", "")
            grbs_land = pygrib.open(f00_path)
            land_grid = get_nam_variable_value(grbs_land, ["LAND"], ["SURFACE"], 0)
            grbs_land.close()

            if land_grid is not None:
                land_keep_mask_1d = (land_grid[domain_mask] >= LAND_MASK_THRESHOLD)
                print(
                    f"{date_str}: land mask keeps {int(land_keep_mask_1d.sum()):,} / "
                    f"{len(land_keep_mask_1d):,} domain pixels"
                )
            else:
                print(f"{date_str}: LAND field not found; keeping all domain pixels.")
        except Exception as e:
            print(f"{date_str}: LAND mask failed ({e}); keeping all domain pixels.")

    if is_test_set or not USE_NEGATIVE_UNDERSAMPLING:
        # Keep the full domain for both train and test when probability interpretability
        # is the goal. This preserves the true pixel-domain event base rate.
        keep_mask_1d = land_keep_mask_1d.copy()
    else:
        # Optional legacy mode: keep all positive pixels and a configurable fraction
        # of negative pixels. Disabled by default in v20.
        pos_mask = (target_1d == 1) & land_keep_mask_1d
        neg_indices = np.where((target_1d == 0) & land_keep_mask_1d)[0]

        np.random.seed(int(date_str))

        sample_size = int(len(neg_indices) * NEGATIVE_SAMPLE_FRAC)
        sample_size = min(sample_size, len(neg_indices))

        sampled_neg_indices = np.random.choice(
            neg_indices,
            size=sample_size,
            replace=False
        )

        keep_mask_1d = np.zeros(len(lats_1d), dtype=bool)
        keep_mask_1d[pos_mask] = True
        keep_mask_1d[sampled_neg_indices] = True

    num_keep = int(keep_mask_1d.sum())

    processed_dict = {
        "Date": np.full(num_keep, date_str),
        "Lat": lats_1d[keep_mask_1d].astype(np.float32),
        "Lon": lons_1d[keep_mask_1d].astype(np.float32),
        TARGET_COLUMN: target_1d[keep_mask_1d].astype(np.int8),
        R40KM_FRACTION_COLUMN: frac_target_1d[keep_mask_1d].astype(np.float32),
        TRAIN_TARGET_COLUMN: (r40_event_count_1d[keep_mask_1d] > 0).astype(np.int8),
        R40KM_TARGET_COUNT_COLUMN: r40_neighbor_count_1d[keep_mask_1d].astype(np.int16),
        R40KM_TARGET_EVENT_COUNT_COLUMN: r40_event_count_1d[keep_mask_1d].astype(np.int16),
        "Obs_LSR_FlashFlood_Report": lsr_target_1d[keep_mask_1d].astype(np.int8),
    }

    for hydro_col, hydro_vals in hydro_target.items():
        if hydro_col == TARGET_COLUMN:
            continue
        processed_dict[hydro_col] = np.asarray(hydro_vals)[keep_mask_1d]

    # Add realtime-available FFG guidance fields as predictors. These are safe because
    # they use the latest FFG at or before RAP init time, not the observed-window FFG.
    processed_dict.update(
        build_guidance_ffg_predictors(
            date_str=date_str,
            lats_1d=lats_1d,
            lons_1d=lons_1d,
            keep_mask_1d=keep_mask_1d,
        )
    )

    # Focused predictor set:
    #   - MCS Maintenance Probability approximation
    #   - PWAT / moisture / thermodynamic fields
    #   - 10m, 850mb, 500mb winds and simple derived wind/shear fields
    #   - soil moisture, where RAP provides it
    #   - precipitation rate, where RAP provides it
    #   - APCP running totals and valid accumulation intervals
    #
    # RAP-specific additions in v20:
    #   MLCAPE, SBCAPE, MLCIN, SBCIN, 2m dewpoint, 2m temperature,
    #   boundary-layer height, precipitation rate, and strengthened PWAT/soil lookup.
    raw_feature_vars = {
        # Moisture / surface thermodynamics.
        "PWAT": (
            ["PWAT", "TCWV"],
            ["ENTIREATMOSPHERE", "ENTIREATMOSPHERECONSIDEREDASASINGLELAYER", "ATMOSPHERE", "UNKNOWN"],
            None
        ),
        "2m_Temperature": (["TMP", "T", "2T"], ["HEIGHTABOVEGROUND"], 2),
        "2m_Dewpoint": (["DPT", "DEWPOINT", "2D"], ["HEIGHTABOVEGROUND"], 2),

        # Instability / inhibition. RAP commonly encodes ML as 90-0 mb AGL and MU as 180-0 mb AGL.
        "SBCAPE": (["CAPE"], ["SURFACE"], 0),
        "SBCIN": (["CIN", "CINH"], ["SURFACE"], 0),
        "MLCAPE": (["CAPE"], ["PRESSUREFROMGROUNDLAYER"], 9000),
        "MLCIN": (["CIN", "CINH"], ["PRESSUREFROMGROUNDLAYER"], 9000),

        # Boundary layer / soil / precip rate.
        "PBL_Height": (["HPBL", "PBLH"], ["SURFACE"], 0),
        "Soil_Moisture": (["SOILW"], ["DEPTHBELOWLANDLAYER"], [0, 10, 100, 1000]),
        "Precip_Rate": (["PRATE"], ["SURFACE"], 0),

        # Winds.
        "10m_U_Wind": (["10U", "UGRD", "U"], ["HEIGHTABOVEGROUND"], 10),
        "10m_V_Wind": (["10V", "VGRD", "V"], ["HEIGHTABOVEGROUND"], 10),
        "850mb_U_Wind": (["U", "UGRD"], ["ISOBARICINHPA"], 850),
        "850mb_V_Wind": (["V", "VGRD"], ["ISOBARICINHPA"], 850),
        "500mb_U_Wind": (["U", "UGRD"], ["ISOBARICINHPA"], 500),
        "500mb_V_Wind": (["V", "VGRD"], ["ISOBARICINHPA"], 500),
    }

    # Ingredients used only to calculate MCS_Maintenance_Prob_RAPCalc.
    # Some of these also appear as direct ML predictors above.
    mmp_ingredient_vars = {
        "MU_CAPE": (["CAPE"], ["PRESSUREFROMGROUNDLAYER"], [18000, 25500, 30000]),
        "ML_CAPE": (["CAPE"], ["PRESSUREFROMGROUNDLAYER"], 9000),
        "Surface_Height": (["HGT", "GH", "OROG"], ["SURFACE"], 0),
    }

    derived_names = [
        "10m_WindSpeed",
        "850mb_WindSpeed",
        "500mb_WindSpeed",
        "Shear_10m_to_500mb",
        "Shear_850_to_500mb",
        "MeanWind_850_500mb",
        "Precip_Rate_mmhr",
        "MCS_Maintenance_Prob_RAPCalc",
    ]

    # APCP GRIB windows found directly in files.
    apcp_running_grids = {0: np.zeros(lats_2d.shape, dtype=np.float32)}
    apcp_interval_grids = {}

    for fhr in FORECAST_HOURS:
        fhr_name = f"fhr_{fhr:02d}h"
        filepath = files_dict.get(fhr_name, "")

        # Stabilize columns across dates.
        for v_name in raw_feature_vars.keys():
            processed_dict[f"{v_name}_{fhr_name}"] = _empty_feature(num_keep)

        for d_name in derived_names:
            processed_dict[f"{d_name}_{fhr_name}"] = _empty_feature(num_keep)

        if not os.path.exists(filepath):
            continue

        try:
            grbs = pygrib.open(filepath)

            full_fields = {}

            # Raw focused features.
            for v_name, (short_names, level_types, lvl) in raw_feature_vars.items():
                grid = get_nam_variable_value(grbs, short_names, level_types, lvl)

                if grid is not None:
                    smoothed_grid = uniform_filter(grid.astype(np.float32), size=3)
                    full_fields[v_name] = smoothed_grid
                    processed_dict[f"{v_name}_{fhr_name}"] = (
                        smoothed_grid[domain_mask][keep_mask_1d].astype(np.float32)
                    )

            # MMP-only ingredients.
            for v_name, (short_names, level_types, lvl) in mmp_ingredient_vars.items():
                grid = get_nam_variable_value(grbs, short_names, level_types, lvl)

                if grid is not None:
                    full_fields[v_name] = uniform_filter(grid.astype(np.float32), size=3)

            # Pressure-level profile for MMP ingredients.
            surface_hgt = full_fields.get("Surface_Height")
            profile = []

            for plev in PROFILE_PRESSURE_LEVELS_HPA:
                gh = get_nam_variable_value(grbs, ["GH", "HGT"], ["ISOBARICINHPA"], plev)
                uu = get_nam_variable_value(grbs, ["U", "UGRD"], ["ISOBARICINHPA"], plev)
                vv = get_nam_variable_value(grbs, ["V", "VGRD"], ["ISOBARICINHPA"], plev)
                tt = get_nam_variable_value(grbs, ["T", "TMP"], ["ISOBARICINHPA"], plev)

                if gh is not None:
                    gh = uniform_filter(gh.astype(np.float32), size=3)
                    if surface_hgt is not None:
                        z_agl = gh - surface_hgt.astype(np.float32)
                    else:
                        z_agl = gh.astype(np.float32)
                else:
                    z_agl = None

                if uu is not None:
                    uu = uniform_filter(uu.astype(np.float32), size=3)
                if vv is not None:
                    vv = uniform_filter(vv.astype(np.float32), size=3)
                if tt is not None:
                    tt = uniform_filter(tt.astype(np.float32), size=3)

                profile.append({
                    "level_hpa": plev,
                    "z_agl": z_agl,
                    "u": uu,
                    "v": vv,
                    "t": tt
                })

            # APCP: read true accumulation windows from GRIB metadata.
            # Convert RAP cycle-relative accumulation windows into 12z-valid-time offsets.
            for start_hr, end_hr, apcp_grid in extract_apcp_windows_from_grib(
                grbs,
                fallback_fhr=(int(fhr) + RAP_FILE_FHR_OFFSET),
                date_str=date_str,
                filepath=filepath
            ):
                if start_hr is None or end_hr is None:
                    continue

                adj_start = int(start_hr) - RAP_FILE_FHR_OFFSET
                adj_end = int(end_hr) - RAP_FILE_FHR_OFFSET

                if adj_end <= 0:
                    continue

                adj_start = max(0, adj_start)

                if adj_end < adj_start:
                    continue

                smoothed_apcp = uniform_filter(apcp_grid.astype(np.float32), size=3)

                if adj_start == 0 and adj_end in APCP_RUNNING_HOURS:
                    apcp_running_grids[adj_end] = smoothed_apcp

                if (adj_start, adj_end) in APCP_INTERVAL_PAIRS:
                    apcp_interval_grids[(adj_start, adj_end)] = smoothed_apcp

            # Derived wind fields.
            u10 = full_fields.get("10m_U_Wind")
            v10 = full_fields.get("10m_V_Wind")

            wind_10m = _safe_speed(u10, v10)
            wind_850 = _safe_speed(full_fields.get("850mb_U_Wind"), full_fields.get("850mb_V_Wind"))
            wind_500 = _safe_speed(full_fields.get("500mb_U_Wind"), full_fields.get("500mb_V_Wind"))

            shear_10m_500 = _safe_shear(
                full_fields.get("10m_U_Wind"),
                full_fields.get("10m_V_Wind"),
                full_fields.get("500mb_U_Wind"),
                full_fields.get("500mb_V_Wind")
            )

            shear_850_500 = _safe_shear(
                full_fields.get("850mb_U_Wind"),
                full_fields.get("850mb_V_Wind"),
                full_fields.get("500mb_U_Wind"),
                full_fields.get("500mb_V_Wind")
            )

            meanwind_850_500 = _safe_mean_wind_speed(
                full_fields.get("850mb_U_Wind"),
                full_fields.get("850mb_V_Wind"),
                full_fields.get("500mb_U_Wind"),
                full_fields.get("500mb_V_Wind")
            )

            max_deep_shear = _max_deep_shear_0_1_to_6_10km(profile, u10, v10)
            lapse_3_8 = _lapse_rate_3_8km(profile)
            meanwind_3_12 = _mean_wind_speed_between_heights(profile, 3000.0, 12000.0)

            mucape_for_mmp = full_fields.get("MU_CAPE")
            if mucape_for_mmp is None:
                mucape_for_mmp = full_fields.get("ML_CAPE")

            mmp_calc = _mmp_namcalc(
                max_shear_ms=max_deep_shear,
                lapse_3_8_km=lapse_3_8,
                mucape=mucape_for_mmp,
                meanwind_3_12_ms=meanwind_3_12
            )

            precip_rate = full_fields.get("Precip_Rate")
            precip_rate_mmhr = None
            if precip_rate is not None:
                # NCEP PRATE is usually kg m^-2 s^-1, equivalent to mm/s liquid water.
                # Multiply by 3600 to get mm/hr. Keep raw PRATE too as Precip_Rate.
                precip_rate_mmhr = (precip_rate.astype(np.float32) * 3600.0).astype(np.float32)

            derived_full = {
                "10m_WindSpeed": wind_10m,
                "850mb_WindSpeed": wind_850,
                "500mb_WindSpeed": wind_500,
                "Shear_10m_to_500mb": shear_10m_500,
                "Shear_850_to_500mb": shear_850_500,
                "MeanWind_850_500mb": meanwind_850_500,
                "Precip_Rate_mmhr": precip_rate_mmhr,
                "MCS_Maintenance_Prob_RAPCalc": mmp_calc,
            }

            for d_name, d_grid in derived_full.items():
                if d_grid is not None:
                    processed_dict[f"{d_name}_{fhr_name}"] = (
                        d_grid[domain_mask][keep_mask_1d].astype(np.float32)
                    )

            grbs.close()

        except Exception:
            # Keep stabilized NaN columns.
            pass

    # APCP running total features.
    # Prefer direct 0-end accumulations when present. If absent, reconstruct from direct intervals.
    for end_fhr in APCP_RUNNING_HOURS:
        col_name = f"APCP_RunTotal_0_{end_fhr:02d}h"
        total_grid = apcp_running_grids.get(end_fhr)

        if total_grid is None:
            total_grid = _sum_apcp_intervals(apcp_interval_grids, end_fhr)

        if total_grid is None:
            processed_dict[col_name] = _empty_feature(num_keep)
        else:
            processed_dict[col_name] = total_grid[domain_mask][keep_mask_1d].astype(np.float32)

    # APCP interval features.
    # Prefer direct interval messages. If absent, difference direct running totals.
    for start_fhr, end_fhr in APCP_INTERVAL_PAIRS:
        col_name = f"APCP_Interval_{start_fhr:02d}_{end_fhr:02d}h"
        interval_grid = apcp_interval_grids.get((start_fhr, end_fhr))

        if interval_grid is None:
            start_total = apcp_running_grids.get(start_fhr)
            end_total = apcp_running_grids.get(end_fhr)
            if start_total is not None and end_total is not None:
                interval_grid = np.clip(end_total - start_total, 0, None).astype(np.float32)

        if interval_grid is None:
            processed_dict[col_name] = _empty_feature(num_keep)
        else:
            processed_dict[col_name] = interval_grid[domain_mask][keep_mask_1d].astype(np.float32)

    # Add derived forecast-precipitation-to-guidance-FFG ratio predictors now that APCP is available.
    add_apcp_to_guidance_ffg_ratio_features(processed_dict)

    # Add 75-km smoothed hydrologic/precipitation feature summaries on the native grid.
    tmp_df_for_features = pd.DataFrame(processed_dict)
    tmp_df_for_features = apply_v28_hydro_feature_engineering(tmp_df_for_features, label=f"daily {date_str} fresh", add_prev24=False)
    processed_dict = {c: tmp_df_for_features[c].to_numpy() for c in tmp_df_for_features.columns}

    # Lightweight APCP sanity marker for this date.
    # If all APCP columns are NaN after this point, inspect APCP_DEBUG_DIR CSVs.
    if APCP_DEBUG:
        try:
            apcp_cols_for_day = [c for c in processed_dict.keys() if "APCP" in c]
            apcp_summary_rows = []
            for c in apcp_cols_for_day:
                vals = np.asarray(processed_dict[c], dtype=np.float32)
                apcp_summary_rows.append({
                    "date": date_str,
                    "column": c,
                    "non_nan": int(np.isfinite(vals).sum()),
                    "unique": int(pd.Series(vals).nunique(dropna=True)),
                    "min": float(np.nanmin(vals)) if np.isfinite(vals).any() else np.nan,
                    "max": float(np.nanmax(vals)) if np.isfinite(vals).any() else np.nan,
                    "mean": float(np.nanmean(vals)) if np.isfinite(vals).any() else np.nan,
                })
            if apcp_summary_rows:
                os.makedirs(APCP_DEBUG_DIR, exist_ok=True)
                pd.DataFrame(apcp_summary_rows).to_csv(
                    os.path.join(APCP_DEBUG_DIR, f"apcp_feature_summary_{date_str}.csv"),
                    index=False
                )
        except Exception:
            pass

    if FEATURE_DEBUG:
        try:
            rows = []
            for c, vals in processed_dict.items():
                if _is_non_predictor_column(c):
                    continue
                arr = np.asarray(vals, dtype=np.float32)
                finite = np.isfinite(arr)
                rows.append({
                    "date": date_str,
                    "column": c,
                    "non_nan": int(finite.sum()),
                    "total": int(len(arr)),
                    "finite_frac": float(finite.mean()) if len(arr) else np.nan,
                    "min": float(np.nanmin(arr)) if finite.any() else np.nan,
                    "max": float(np.nanmax(arr)) if finite.any() else np.nan,
                    "mean": float(np.nanmean(arr)) if finite.any() else np.nan,
                })
            if rows:
                os.makedirs(FEATURE_DEBUG_DIR, exist_ok=True)
                pd.DataFrame(rows).to_csv(
                    os.path.join(FEATURE_DEBUG_DIR, f"rap_feature_summary_{date_str}.csv"),
                    index=False
                )
        except Exception:
            pass

    return pd.DataFrame(processed_dict)


def get_daily_chunk_path(date_str):
    return os.path.join(PIXEL_CHUNK_DIR, f"pixel_features_{date_str}.parquet")


def daily_chunk_exists(date_str):
    path = get_daily_chunk_path(date_str)
    return os.path.exists(path) and os.path.getsize(path) > 1024


def get_failed_date_marker_path(date_str):
    return os.path.join(FAILED_DATE_MARKER_DIR, f"failed_{date_str}.txt")


def failed_date_marker_exists(date_str):
    if FORCE_RETRY_FAILED_DATES or not USE_FAILED_DATE_MARKERS:
        return False
    path = get_failed_date_marker_path(date_str)
    return os.path.exists(path) and os.path.getsize(path) > 0


def mark_failed_date(date_str, reason):
    if not USE_FAILED_DATE_MARKERS:
        return
    try:
        os.makedirs(FAILED_DATE_MARKER_DIR, exist_ok=True)
        with open(get_failed_date_marker_path(date_str), "w") as f:
            f.write(f"date={date_str}\n")
            f.write(f"reason={reason}\n")
            f.write(f"created_utc={datetime.now(timezone.utc).replace(tzinfo=None).isoformat()}Z\n")
    except Exception as exc:
        print(f"  -> Could not write failed-date marker for {date_str}: {exc}")


def save_daily_chunk(date_str, df_day):
    """
    Save one completed date immediately.

    The write is atomic:
      1. write to *.tmp
      2. os.replace(tmp, final)

    This prevents a half-written parquet file from being treated as complete after an interruption.
    """
    if df_day is None or len(df_day) == 0:
        return None

    if STRICT_PROJECT_MOUNT_CHECK_FOR_DATA_WRITES:
        require_project_mount_live(f"saving daily chunk for {date_str}")

    final_path = get_daily_chunk_path(date_str)
    tmp_path = final_path + ".tmp"

    os.makedirs(PIXEL_CHUNK_DIR, exist_ok=True)

    if os.path.exists(tmp_path):
        os.remove(tmp_path)

    df_day.to_parquet(tmp_path, index=False)
    os.replace(tmp_path, final_path)

    return final_path


def get_existing_daily_chunk_paths(all_dates):
    return [get_daily_chunk_path(d) for d in all_dates if daily_chunk_exists(d)]


def _master_union_columns_from_parquet_files(paths):
    """Return a stable union of parquet columns without loading all row data."""
    union_cols = []
    seen = set()
    try:
        import pyarrow.parquet as pq
        for path in paths:
            schema = pq.read_schema(path)
            for col in schema.names:
                if col not in seen:
                    seen.add(col)
                    union_cols.append(col)
    except Exception:
        # Fallback: metadata read with pandas if pyarrow schema inspection fails.
        for path in paths:
            cols = list(pd.read_parquet(path).columns)
            for col in cols:
                if col not in seen:
                    seen.add(col)
                    union_cols.append(col)
    return union_cols


def _normalize_master_batch_for_write(df, union_cols):
    """Make batch columns/order stable before appending it as a parquet row group."""
    # Missing columns here are schema alignment only, not model-feature padding.
    # Daily chunks can differ when older chunks are reused or some GRIB fields are unavailable.
    for col in union_cols:
        if col not in df.columns:
            df[col] = np.nan
    df = df.reindex(columns=union_cols)

    if "Date" in df.columns:
        df["Date"] = df["Date"].astype(str)
    if "Year" in df.columns:
        df["Year"] = pd.to_numeric(df["Year"], errors="coerce").astype("float32")

    # Convert object columns that are actually numeric. Keep Date/string metadata as strings.
    for col in df.columns:
        if col == "Date":
            continue
        if df[col].dtype == object:
            converted = pd.to_numeric(df[col], errors="coerce")
            if converted.notna().sum() > 0:
                df[col] = converted.astype("float32")
    return df




def _parquet_columns(path):
    """Return parquet column names without reading the full table."""
    try:
        import pyarrow.parquet as pq
        return list(pq.ParquetFile(path).schema_arrow.names)
    except Exception as exc:
        raise RuntimeError(f"Could not read parquet metadata for {path}: {exc}") from exc


def _date_set_from_master_parquet(path):
    """Read only the Date column to check master-parquet completeness."""
    if not os.path.exists(path):
        return set()
    date_df = None
    try:
        date_df = pd.read_parquet(path, columns=["Date"])
        if "Date" not in date_df.columns:
            return set()
        return set(date_df["Date"].astype(str).unique())
    finally:
        try:
            del date_df
        except Exception:
            pass
        gc.collect()


def _is_slim_master_training_column(col):
    """
    Columns to keep when loading the master for training.

    The full master parquet intentionally keeps raw/debug RAP fields, but loading all of
    them at once can OOM. The v28 model is radius-only, so training needs only metadata,
    the single target/diagnostic columns, optional APCP filter support, and final R75km
    Mean/Min/Max/Std predictors. Previous-day features are rebuilt from Date/Lat/Lon and
    observed MRMS/FFG diagnostics after the slim load.
    """
    c = str(col)
    always = {
        "Date", "Lat", "Lon", "Year",
        TARGET_COLUMN, TRAIN_TARGET_COLUMN,
        R40KM_FRACTION_COLUMN, R40KM_TARGET_COUNT_COLUMN, R40KM_TARGET_EVENT_COUNT_COLUMN,
        "Obs_LSR_FlashFlood_Report",
        TRAIN_FIT_APCP_FILTER_PREFERRED_COL,
    }
    if c in always:
        return True
    if c.startswith("PrevDay_MRMS_FFG_"):
        return True
    if USE_RADIUS_ONLY_MODEL_FEATURES and _is_radius_smoothed_stat_feature(c):
        return True
    if (not USE_RADIUS_ONLY_MODEL_FEATURES) and not _is_non_predictor_column(c):
        return True
    return False


def get_master_training_columns(path):
    """Return the bounded-memory column subset used for training."""
    all_cols = _parquet_columns(path)
    keep = [c for c in all_cols if _is_slim_master_training_column(c)]

    required = ["Date", "Lat", "Lon", TARGET_COLUMN]
    missing_required = [c for c in required if c not in keep]
    if missing_required:
        raise RuntimeError(
            f"Master parquet is missing required training columns {missing_required}. "
            f"Found {len(all_cols):,} columns in {path}."
        )

    n_radius = sum(_is_radius_smoothed_stat_feature(c) for c in keep)
    print(
        f"Slim master read: keeping {len(keep):,} / {len(all_cols):,} columns "
        f"({n_radius:,} R75km radius-stat predictors before availability filtering)."
    )
    return keep



def _downcast_training_frame_inplace(df):
    """Reduce pandas memory after reading/sampling master parquet columns."""
    if "Date" in df.columns:
        df["Date"] = df["Date"].astype(str)
    for col in list(df.columns):
        if col == "Date":
            continue
        if col in {TARGET_COLUMN, TRAIN_TARGET_COLUMN, "Obs_LSR_FlashFlood_Report"}:
            df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0).astype(np.int8)
        elif col in {R40KM_TARGET_COUNT_COLUMN, R40KM_TARGET_EVENT_COUNT_COLUMN}:
            df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0).astype(np.float32)
        else:
            df[col] = pd.to_numeric(df[col], errors="coerce").astype(np.float32)
    return df


def _count_master_train_test_rows(path):
    """Count rows in train years vs formal test years using only the Date column."""
    import pyarrow.parquet as pq
    pf = pq.ParquetFile(path)
    test_years = set(str(y) for y in FORMAL_TEST_YEARS)
    n_train = 0
    n_test = 0
    for rg in range(pf.num_row_groups):
        tbl = pf.read_row_group(rg, columns=["Date"])
        d = tbl.column("Date").to_pandas().astype(str)
        y = d.str[:4]
        is_test = y.isin(test_years).to_numpy()
        n_test += int(is_test.sum())
        n_train += int((~is_test).sum())
        del tbl, d, y, is_test
        gc.collect()
    return n_train, n_test


def _read_master_parquet_stream_sampled(path, columns):
    """
    Read a row-sampled version of the slim master parquet.

    This is the critical V3 fix.  Even 478 slim columns are too large at 6.5M rows.
    We therefore read one parquet row group at a time and keep a uniform random sample
    separately for train years and formal test years. This preserves the target base rate
    far better than class undersampling while avoiding the OS OOM killer.
    """
    import pyarrow.parquet as pq

    max_train = int(globals().get("MASTER_MAX_TRAIN_ROWS", 1000000))
    max_test = int(globals().get("MASTER_MAX_TEST_ROWS", 300000))
    rng = np.random.default_rng(int(globals().get("MASTER_ROW_SAMPLE_RANDOM_STATE", 42)))
    test_years = set(str(y) for y in FORMAL_TEST_YEARS)

    n_train_total, n_test_total = _count_master_train_test_rows(path)
    p_train = 1.0 if max_train <= 0 or n_train_total <= max_train else float(max_train) / max(1, n_train_total)
    p_test = 1.0 if max_test <= 0 or n_test_total <= max_test else float(max_test) / max(1, n_test_total)

    print(
        "Master row sampling enabled before pandas materialization:\n"
        f"  train-year rows available={n_train_total:,}, cap={max_train:,}, keep_prob={p_train:.4f}\n"
        f"  test-year rows available={n_test_total:,}, cap={max_test:,}, keep_prob={p_test:.4f}"
    )

    pf = pq.ParquetFile(path)
    parts = []
    kept_train = 0
    kept_test = 0

    for rg in tqdm(range(pf.num_row_groups), desc="Reading/sampling slim master row groups", unit="rowgrp"):
        tbl = pf.read_row_group(rg, columns=columns)
        df_rg = tbl.to_pandas()
        del tbl

        df_rg["Date"] = df_rg["Date"].astype(str)
        years = df_rg["Date"].str[:4]
        is_test = years.isin(test_years).to_numpy()
        is_train = ~is_test

        keep = np.zeros(len(df_rg), dtype=bool)
        if is_train.any():
            keep[is_train] = rng.random(int(is_train.sum())) < p_train
        if is_test.any():
            keep[is_test] = rng.random(int(is_test.sum())) < p_test

        if keep.any():
            part = df_rg.loc[keep].copy()
            kept_test += int(years.loc[keep].isin(test_years).sum())
            kept_train += int(len(part) - years.loc[keep].isin(test_years).sum())
            parts.append(_downcast_training_frame_inplace(part))

        del df_rg, years, is_test, is_train, keep
        gc.collect()

    if not parts:
        raise RuntimeError("Master row sampling kept zero rows. Increase MASTER_MAX_TRAIN_ROWS / MASTER_MAX_TEST_ROWS or disable sampling.")

    out = pd.concat(parts, ignore_index=True, sort=False)
    del parts
    out = _downcast_training_frame_inplace(out)
    gc.collect()

    print(
        f"Sampled slim master loaded: rows={len(out):,} "
        f"(train-year={kept_train:,}, test-year={kept_test:,}), columns={len(out.columns):,}"
    )
    return out


def read_master_parquet_for_training(path=None):
    """
    Load the master parquet with a bounded column set and, by default, a bounded row set.

    V2 still OOMed because 6.5M rows x 478 slim columns is too large once pandas/XGBoost
    make copies. V3 samples rows while streaming parquet row groups before materializing
    the dataframe. This is uniform row sampling by train/test year group, not class-based
    negative undersampling.
    """
    path = path or PIXEL_PARQUET
    slim = str(os.environ.get("HAZARD_ML_MASTER_SLIM_READ", "1")).strip().lower() not in {"0", "false", "no", "n"}

    if not slim:
        print("WARNING: HAZARD_ML_MASTER_SLIM_READ=0; loading full master parquet and risking OOM.")
        return pd.read_parquet(path)

    cols = get_master_training_columns(path)
    stream_sample = bool(globals().get("MASTER_STREAM_ROW_SAMPLE", True))
    max_train = int(globals().get("MASTER_MAX_TRAIN_ROWS", 1000000))
    max_test = int(globals().get("MASTER_MAX_TEST_ROWS", 300000))

    if stream_sample and (max_train > 0 or max_test > 0):
        return _read_master_parquet_stream_sampled(path, cols)

    print("WARNING: master row sampling disabled; loading all slim rows may OOM.")
    df = pd.read_parquet(path, columns=cols)
    df = _downcast_training_frame_inplace(df)
    gc.collect()
    return df


def combine_daily_chunks_to_master(all_dates):
    """
    Combine existing daily parquet chunks into the master parquet using bounded memory.

    v33 slim-master variant:
      * inspects daily schemas without loading row data
      * writes only training/viewer-needed columns, not the full raw/debug schema
      * reads each batch with an explicit column subset
      * writes pyarrow row groups and does not materialize the full master dataframe

    This is not model-feature padding. Missing columns are only aligned at the
    parquet schema level before feature selection; the model feature list is still
    validated later before fitting/inference.
    """
    chunk_paths = get_existing_daily_chunk_paths(all_dates)

    if not chunk_paths:
        raise RuntimeError(
            f"No daily parquet chunks found in {PIXEL_CHUNK_DIR}. "
            "Cannot build the master pixel database."
        )

    missing_dates = [d for d in all_dates if not daily_chunk_exists(d)]

    print(f"\nCombining {len(chunk_paths)} daily parquet chunks into SLIM master dataset with memory-safe row-group writer...")
    if missing_dates:
        print(
            f"  -> Warning: {len(missing_dates)} dates do not have chunks and will be omitted. "
            f"First few missing dates: {missing_dates[:10]}"
        )

    if STRICT_PROJECT_MOUNT_CHECK_FOR_DATA_WRITES:
        require_project_mount_live("combining daily chunks into slim master parquet")

    tmp_master = PIXEL_PARQUET + ".tmp"
    if os.path.exists(tmp_master):
        try:
            if os.path.isdir(tmp_master):
                shutil.rmtree(tmp_master)
            else:
                os.remove(tmp_master)
        except Exception:
            pass

    try:
        import pyarrow as pa
        import pyarrow.parquet as pq
    except Exception as exc:
        raise RuntimeError(
            "pyarrow is required for memory-safe master parquet streaming. "
            "Install/enable pyarrow or reduce the dataset enough for the old concat path."
        ) from exc

    path_cols = {}
    union_cols_all = []
    seen = set()
    for path in chunk_paths:
        cols = list(pq.ParquetFile(path).schema_arrow.names)
        path_cols[path] = cols
        for col in cols:
            if col not in seen:
                seen.add(col)
                union_cols_all.append(col)

    slim_write = str(os.environ.get("HAZARD_ML_MASTER_COMBINE_SLIM_WRITE", "1")).strip().lower() not in {"0", "false", "no", "n"}
    if slim_write:
        union_cols = [c for c in union_cols_all if _is_slim_master_training_column(c)]
    else:
        union_cols = union_cols_all

    required_for_master = ["Date", "Lat", "Lon", TARGET_COLUMN, TRAIN_TARGET_COLUMN]
    missing_required = [c for c in required_for_master if c not in union_cols]
    if missing_required:
        raise RuntimeError(
            f"Slim master combine would omit required columns {missing_required}. "
            f"First 100 available union columns: {union_cols_all[:100]}"
        )

    n_radius_features = sum(_is_radius_smoothed_stat_feature(c) for c in union_cols)
    batch_size = max(1, int(globals().get("MASTER_COMBINE_BATCH_SIZE", 2)))
    print(f"Master combine batch size: {batch_size} daily chunks")
    print(f"Full daily union column count: {len(union_cols_all):,}")
    print(f"Slim master output column count: {len(union_cols):,} ({n_radius_features:,} radius-stat predictors)")
    print(f"Slim master output path: {PIXEL_PARQUET}")

    writer = None
    total_rows = 0
    try:
        for start_i in tqdm(range(0, len(chunk_paths), batch_size), desc="Writing slim master parquet batches", unit="batch"):
            batch_paths = chunk_paths[start_i:start_i + batch_size]
            batch_frames = []
            for path in batch_paths:
                cols_here = [c for c in union_cols if c in path_cols.get(path, [])]
                if not cols_here:
                    raise RuntimeError(f"No requested slim columns found in daily chunk: {path}")
                batch_frames.append(pd.read_parquet(path, columns=cols_here))

            batch_df = pd.concat(batch_frames, ignore_index=True, sort=False)
            del batch_frames
            batch_df = _normalize_master_batch_for_write(batch_df, union_cols)

            table = pa.Table.from_pandas(batch_df, preserve_index=False)
            if writer is None:
                writer = pq.ParquetWriter(tmp_master, table.schema, compression="snappy")
            else:
                table = table.cast(writer.schema, safe=False)

            writer.write_table(table)
            total_rows += len(batch_df)

            del table, batch_df
            gc.collect()
    finally:
        if writer is not None:
            writer.close()

    os.replace(tmp_master, PIXEL_PARQUET)
    print(f"Saved SLIM master pixel database to: {PIXEL_PARQUET} rows={total_rows:,}", flush=True)

    print("Loading slim training columns from SLIM master parquet...", flush=True)
    return read_master_parquet_for_training(PIXEL_PARQUET)


@ray.remote(num_cpus=0.1)
def ray_worker_smoke_test():
    """Small import/env check that runs on a Ray worker before launching expensive date tasks."""
    import os as _os
    import socket as _socket
    try:
        import requests as _requests
        requests_version = _requests.__version__
    except Exception as exc:
        requests_version = f"requests import failed: {exc!r}"
    try:
        import pygrib as _pygrib  # noqa: F401
        pygrib_ok = True
    except Exception as exc:
        pygrib_ok = f"pygrib import failed: {exc!r}"
    return {
        "host": _socket.gethostname(),
        "pid": _os.getpid(),
        "requests_version": requests_version,
        "pygrib_ok": pygrib_ok,
        "REQUESTS_CA_BUNDLE": _os.environ.get("REQUESTS_CA_BUNDLE"),
        "SSL_CERT_FILE": _os.environ.get("SSL_CERT_FILE"),
    }


def run_ray_worker_smoke_test():
    if not RUN_RAY_WORKER_SMOKE_TEST:
        return
    print("Running Ray worker smoke test...")
    try:
        refs = [ray_worker_smoke_test.remote() for _ in range(min(4, max(1, int(ray.cluster_resources().get("CPU", 1)))))]
        results = ray.get(refs)
        hosts = sorted({str(r.get("host")) for r in results})
        print(f"Ray worker smoke test OK on hosts: {hosts}")
        first = results[0] if results else {}
        print(f"  pygrib_ok={first.get('pygrib_ok')} REQUESTS_CA_BUNDLE={first.get('REQUESTS_CA_BUNDLE')}")
    except Exception as exc:
        raise RuntimeError(
            "Ray workers failed the startup smoke test before extraction. "
            "This is a Ray/Python environment problem, not a date-specific MRMS/RAP issue. "
            "Try reducing DATA_EXTRACTION_MAX_IN_FLIGHT or use USE_RAY_FOR_DATA_EXTRACTION=False."
        ) from exc


@ray.remote(max_calls=RAY_DATE_TASK_MAX_CALLS)
def process_daily_pixel_data_ray(date_str, nam_dir, domain_vars, is_test_set=False):
    """
    Ray wrapper around process_daily_pixel_data.

    The worker is recycled after several date tasks, not after every date.
    max_calls=1 caused too much Ray worker startup/registration churn for the MRMS-heavy v24 target build.
    """
    return process_daily_pixel_data(
        date_str=date_str,
        nam_dir=nam_dir,
        domain_vars=domain_vars,
        is_test_set=is_test_set
    )


def build_pixel_database_with_ray(all_dates, test_dates_set, domain_vars):
    """
    Distribute one date per Ray task across the cluster and collect in completion order.

    v26f behavior:
      - keeps only a conservative number of in-flight date tasks
      - warns about long-running dates instead of falsely cancelling at 900 s
      - optional hard cancellation only if HAZARD_ML_RAY_HARD_TIMEOUT_S > 0
      - saves each completed date immediately as a daily parquet chunk
    """
    import time
    import traceback

    existing_paths = get_existing_daily_chunk_paths(all_dates)
    dates_to_process = [d for d in all_dates if not daily_chunk_exists(d) and not failed_date_marker_exists(d)]

    print(f"\nDaily chunk cache: {PIXEL_CHUNK_DIR}")
    print(f"Existing completed date chunks: {len(existing_paths)}")
    print(f"Dates still needing extraction: {len(dates_to_process)}")
    if USE_FAILED_DATE_MARKERS and not FORCE_RETRY_FAILED_DATES:
        skipped_failed = [d for d in all_dates if failed_date_marker_exists(d) and not daily_chunk_exists(d)]
        if skipped_failed:
            print(f"Dates skipped due to previous hydro-target failure markers: {len(skipped_failed)}")
            print(f"  First few skipped failed dates: {skipped_failed[:10]}")

    if not dates_to_process:
        print("All daily chunks already exist. Skipping Ray extraction.")
        return existing_paths

    cluster_cpus = int(ray.cluster_resources().get("CPU", 1))
    if DATA_EXTRACTION_MAX_IN_FLIGHT is None:
        max_in_flight = max(1, min(len(dates_to_process), cluster_cpus))
    else:
        max_in_flight = max(1, int(DATA_EXTRACTION_MAX_IN_FLIGHT))
    max_in_flight = min(max_in_flight, len(dates_to_process))

    poll_s = float(os.environ.get("HAZARD_ML_RAY_POLL_S", "30"))
    stall_warn_s = float(os.environ.get("HAZARD_ML_RAY_STALL_WARN_S", "900"))
    hard_timeout_s = float(os.environ.get("HAZARD_ML_RAY_HARD_TIMEOUT_S", "0"))

    print(f"\nDispatching Ray-distributed date extraction for {len(dates_to_process)} remaining dates...")
    print(f"Ray cluster CPUs visible:        {cluster_cpus}")
    print(f"CPUs requested per date task:    {DATA_EXTRACTION_CPUS_PER_TASK}")
    print(f"Max in-flight date tasks:        {max_in_flight}")
    print(f"Ray date-task max_calls:         {RAY_DATE_TASK_MAX_CALLS}")
    print(f"Ray poll interval seconds:       {poll_s:g}")
    print(f"Ray stall warning seconds:       {stall_warn_s:g}")
    print(f"Ray hard timeout seconds:        {hard_timeout_s:g} (0 means do not cancel slow dates)")

    domain_vars_ref = ray.put(domain_vars)
    completed_paths = list(existing_paths)
    date_iter = iter(dates_to_process)
    pending = {}          # ObjectRef -> date string
    submit_time = {}      # ObjectRef -> monotonic time
    last_warn_time = {}   # ObjectRef -> monotonic time

    def submit_next():
        try:
            d_str = next(date_iter)
        except StopIteration:
            return False

        task_options = {"num_cpus": DATA_EXTRACTION_CPUS_PER_TASK}
        if USE_RAY_SPREAD_SCHEDULING:
            task_options["scheduling_strategy"] = "SPREAD"

        ref = process_daily_pixel_data_ray.options(**task_options).remote(
            d_str,
            RAP_DIR,
            domain_vars_ref,
            d_str in test_dates_set,
        )
        pending[ref] = d_str
        submit_time[ref] = time.monotonic()
        last_warn_time[ref] = 0.0
        return True

    for _ in range(max_in_flight):
        submit_next()

    with tqdm(total=len(dates_to_process), desc="Extracting/saving daily chunks via Ray") as pbar:
        while pending:
            done_refs, _ = ray.wait(list(pending.keys()), num_returns=1, timeout=poll_s)

            if not done_refs:
                now = time.monotonic()
                for ref, d_str in list(pending.items()):
                    age = now - submit_time.get(ref, now)
                    if age >= stall_warn_s and (now - last_warn_time.get(ref, 0.0)) >= stall_warn_s:
                        last_warn_time[ref] = now
                        print(
                            f"  -> Ray task for {d_str} has been pending/running {age/60.0:.1f} min; "
                            "not cancelling. Set HAZARD_ML_RAY_HARD_TIMEOUT_S>0 only if you truly want cancellation."
                        )
                    if hard_timeout_s > 0 and age >= hard_timeout_s:
                        print(f"  -> Ray task for {d_str} exceeded hard timeout {hard_timeout_s:.0f}s; cancelling and marking failed.")
                        try:
                            ray.cancel(ref, force=True)
                        except Exception as exc:
                            print(f"     ray.cancel failed for {d_str}: {exc}")
                        pending.pop(ref, None)
                        mark_failed_date(d_str, f"Ray task exceeded hard timeout {hard_timeout_s:.0f}s")
                        pbar.update(1)
                        submit_next()
                continue

            for ref in done_refs:
                d_str = pending.pop(ref)
                submit_time.pop(ref, None)
                last_warn_time.pop(ref, None)
                try:
                    df_day = ray.get(ref)
                    chunk_path = save_daily_chunk(d_str, df_day)
                    if chunk_path is not None:
                        completed_paths.append(chunk_path)
                    else:
                        print(f"  -> No usable dataframe produced for {d_str}; not cached. Marking failed so it is not retried every run.")
                        mark_failed_date(d_str, "process_daily_pixel_data returned no usable dataframe")
                except Exception as e:
                    print(f"  -> Ray extraction failed for {d_str}: {e}")
                    traceback.print_exc()
                    mark_failed_date(d_str, f"Ray extraction exception: {repr(e)}")

                pbar.update(1)
                submit_next()

    return get_existing_daily_chunk_paths(all_dates)

def build_pixel_database_locally(all_dates, test_dates_set, domain_vars):
    """
    Local fallback version, using only this machine.

    Also writes one parquet chunk per completed date, so it is resumable too.
    """
    existing_paths = get_existing_daily_chunk_paths(all_dates)
    dates_to_process = [d for d in all_dates if not daily_chunk_exists(d) and not failed_date_marker_exists(d)]

    print(f"\nDaily chunk cache: {PIXEL_CHUNK_DIR}")
    print(f"Existing completed date chunks: {len(existing_paths)}")
    print(f"Dates still needing extraction: {len(dates_to_process)}")

    if not dates_to_process:
        print("All daily chunks already exist. Skipping local extraction.")
        return existing_paths

    print(f"\nDispatching {MAX_WORKERS} local parallel workers for {len(dates_to_process)} remaining dates...")

    completed_paths = list(existing_paths)

    with concurrent.futures.ProcessPoolExecutor(max_workers=MAX_WORKERS) as executor:
        futures = {}

        for d_str in dates_to_process:
            is_test = d_str in test_dates_set

            future = executor.submit(
                process_daily_pixel_data,
                d_str,
                RAP_DIR,
                domain_vars,
                is_test
            )
            futures[future] = d_str

        for future in tqdm(
            concurrent.futures.as_completed(futures),
            total=len(futures),
            desc="Extracting/saving daily chunks locally"
        ):
            d_str = futures[future]

            try:
                df_day = future.result()
                chunk_path = save_daily_chunk(d_str, df_day)

                if chunk_path is not None:
                    completed_paths.append(chunk_path)
                else:
                    print(f"  -> No usable dataframe produced for {d_str}; not cached. Marking failed so it is not retried every run.")
                    mark_failed_date(d_str, "process_daily_pixel_data returned no usable dataframe")
            except Exception as e:
                print(f"  -> Local extraction failed for {d_str}: {e}")
                mark_failed_date(d_str, f"Local extraction exception: {repr(e)}")

    return get_existing_daily_chunk_paths(all_dates)

