def safe_roc_auc(y_true, probs):
    try:
        return roc_auc_score(y_true, probs)
    except ValueError:
        return np.nan


def get_base_estimator_from_model_obj(model_obj):
    """
    Recover a fitted base estimator for SHAP/feature importance.

    v20d saves raw uncalibrated estimators directly. Older cached runs may still
    contain wrapper objects, so keep a small compatibility fallback.
    """
    if hasattr(model_obj, "base_model"):
        return model_obj.base_model

    if hasattr(model_obj, "feature_importances_") or hasattr(model_obj, "coef_"):
        return model_obj

    if hasattr(model_obj, "final_estimator_"):
        return model_obj.final_estimator_

    if hasattr(model_obj, "estimators_") and model_obj.estimators_:
        return model_obj.estimators_[0]

    if hasattr(model_obj, "calibrated_classifiers_"):
        first = model_obj.calibrated_classifiers_[0]

        if hasattr(first, "estimator"):
            return first.estimator

        if hasattr(first, "base_estimator"):
            return first.base_estimator

    raise AttributeError("Could not find fitted base estimator inside model object.")



def validate_mode_csv_inputs():
    """Fail fast if expected MODE CSVs are missing from the project mount."""
    mode_paths = {
        "2018_2023": MODE_2018_CSV,
        "2024": MODE_2024_CSV,
        "2025": MODE_2025_CSV,
    }
    existing = {k: os.path.exists(v) for k, v in mode_paths.items()}

    print("\nMODE CSV availability:")
    for label, path in mode_paths.items():
        status = "FOUND" if existing[label] else "MISSING"
        print(f"  {label:9s}: {status:7s} {path}")

    if not existing["2018_2023"]:
        raise FileNotFoundError(
            "Required 2018-2023 MODE CSV is missing. This usually means the mtdesktop/sshfs "
            f"mount is disconnected or hidden: {MODE_2018_CSV}"
        )

    missing_test = [label for label in ["2024", "2025"] if not existing[label]]
    if missing_test and REQUIRE_FORMAL_TEST_MODE_CSVS:
        raise FileNotFoundError(
            "Formal test MODE CSV(s) are missing: "
            + ", ".join(missing_test)
            + ". Remount /home/tyreekfrazier/ISU_Research before training; otherwise the "
              "script will build a dataset with zero 2024/2025 test rows."
        )

    return existing


def get_formal_test_dates_from_mode_csvs(all_dates):
    """Return YYYYMMDD strings from the 2024/2025 MODE CSVs that survived RAP filtering."""
    dfs_test_only = [
        pd.read_csv(f)
        for f in [MODE_2024_CSV, MODE_2025_CSV]
        if os.path.exists(f)
    ]

    test_dates_set = set()
    if dfs_test_only:
        df_test_meta = pd.concat(dfs_test_only, ignore_index=True)
        for _, row in df_test_meta.iterrows():
            try:
                test_dates_set.add(f"{int(row['Year'])}{int(row['Month']):02d}{int(row['Day']):02d}")
            except Exception:
                continue

    test_dates_set = set(test_dates_set).intersection(set(map(str, all_dates)))
    print(f"Formal 2024/2025 MODE test dates after RAP filtering: {len(test_dates_set):,}")
    if test_dates_set:
        sample = sorted(test_dates_set)
        print(f"  first formal test dates: {sample[:5]}")
        print(f"  last formal test dates:  {sample[-5:]}")
    return test_dates_set


def _prepare_domain_vars_for_extraction(all_dates):
    """Find/open one RAP file only to establish the RAP domain grid."""
    print("\nConstructing Master RAP Pixel-Level Environment Database...")
    print("Preparing/validating a RAP 09z f03 domain sample before launching extraction...")

    sample_candidate_dates = list(all_dates)[:DOMAIN_SAMPLE_SEARCH_LIMIT]
    sample_path = None
    for sample_date in tqdm(sample_candidate_dates, desc="Preparing RAP domain sample", unit="date"):
        sample_path = ensure_nam_forecast_file(sample_date, 0, RAP_DIR)
        if sample_path is not None and validate_nam_forecast_file(sample_path, sample_date, 0):
            tqdm.write(f"Using validated RAP domain sample: {sample_path}")
            break
        sample_path = None

    if sample_path is None:
        raise FileNotFoundError(
            "No validated RAP 09z f03 domain-sample GRIB2 file found or downloaded. "
            "Check internet access, mount state, prior feature chunks, and RAP date availability."
        )

    return get_nam_domain_mask(sample_path)


def build_or_update_pixel_master(all_dates, test_dates_set):
    """Build/update master parquet; rebuild incomplete cached masters left by dropped mounts."""
    expected_dates = set(map(str, all_dates))

    if os.path.exists(PIXEL_PARQUET):
        print(f"\nChecking cached Pixel Database from {PIXEL_PARQUET}...")
        cached_dates = _date_set_from_master_parquet(PIXEL_PARQUET)
        missing_expected = sorted(expected_dates - cached_dates)
        missing_formal_test = sorted(set(test_dates_set) - cached_dates)

        print(f"Cached master dates: {len(cached_dates):,} | expected MODE/RAP-filtered dates: {len(expected_dates):,}")
        if missing_expected:
            print(f"Cached master is missing {len(missing_expected):,} expected dates. First missing: {missing_expected[:10]}")
        if missing_formal_test:
            print(f"Cached master is missing {len(missing_formal_test):,} formal 2024/2025 test dates. First missing: {missing_formal_test[:10]}")

        if not missing_expected:
            print("Cached master is complete; loading slim training columns only.")
            return read_master_parquet_for_training(PIXEL_PARQUET)

        if not REBUILD_INCOMPLETE_MASTER_PARQUET:
            raise RuntimeError(
                "Cached master parquet is incomplete and REBUILD_INCOMPLETE_MASTER_PARQUET=False. "
                f"Delete or rebuild: {PIXEL_PARQUET}"
            )

        print("Rebuilding/updating missing daily chunks, then recombining the v28 master parquet...")
        gc.collect()
    else:
        print(f"\nNo cached Pixel Database found at {PIXEL_PARQUET}; building from daily chunks/extraction.")

    domain_vars = _prepare_domain_vars_for_extraction(all_dates)

    if USE_RAY_FOR_DATA_EXTRACTION:
        chunk_paths = build_pixel_database_with_ray(all_dates=all_dates, test_dates_set=test_dates_set, domain_vars=domain_vars)
    else:
        chunk_paths = build_pixel_database_locally(all_dates, test_dates_set, domain_vars)

    if not chunk_paths:
        raise RuntimeError("No daily parquet chunks were produced. Check RAP/MRMS/FFG files and MODE dates.")

    completed_frac = len(chunk_paths) / max(1, len(all_dates))
    print(f"Completed daily chunks before training: {len(chunk_paths):,} / {len(all_dates):,} ({completed_frac:.1%})")
    if completed_frac < float(MIN_COMPLETED_DATE_FRACTION_FOR_TRAINING):
        raise RuntimeError(
            f"Only {len(chunk_paths):,}/{len(all_dates):,} dates produced daily chunks ({completed_frac:.1%}). "
            f"This is below MIN_COMPLETED_DATE_FRACTION_FOR_TRAINING={MIN_COMPLETED_DATE_FRACTION_FOR_TRAINING:.0%}. "
            "Do not train on this incomplete case set; inspect hydro target debug CSVs for missing MRMS/FFG."
        )

    return combine_daily_chunks_to_master(all_dates)


def split_train_test_by_formal_years_or_holdout(df_master, formal_test_dates):
    """Use real 2024/2025 test rows, or a date-level temporal fallback holdout if necessary."""
    df_master = df_master.copy()
    df_master["Date"] = df_master["Date"].astype(str)
    df_master["Year"] = df_master["Date"].str[:4].astype(int)

    formal_mask = df_master["Date"].isin(set(map(str, formal_test_dates)))
    if not formal_mask.any():
        formal_mask = df_master["Year"].isin(list(FORMAL_TEST_YEARS))

    if formal_mask.any():
        df_test = df_master[formal_mask].copy()
        df_train = df_master[~formal_mask].copy()
        split_label = f"formal MODE test years {FORMAL_TEST_YEARS}"
    else:
        if not USE_DATE_HOLDOUT_IF_NO_FORMAL_TEST_ROWS:
            raise RuntimeError(
                "No 2024/2025/formal test rows are present in df_master. This usually means an incomplete "
                "cached master parquet was loaded or the test MODE CSVs were unavailable when the dataset was built."
            )

        unique_dates = sorted(df_master["Date"].unique())
        if len(unique_dates) < 2:
            raise RuntimeError("Need at least two dates to create a fallback date holdout; df_master has too few dates.")

        n_holdout = int(np.ceil(len(unique_dates) * float(DATE_HOLDOUT_FRACTION)))
        n_holdout = max(int(DATE_HOLDOUT_MIN_DATES), n_holdout)
        n_holdout = min(max(1, n_holdout), len(unique_dates) - 1)
        holdout_dates = set(unique_dates[-n_holdout:])

        print("\nWARNING: No formal 2024/2025 test rows found in the master dataframe.")
        print(
            f"Using fallback temporal date holdout: {n_holdout:,}/{len(unique_dates):,} dates "
            f"({min(holdout_dates)} through {max(holdout_dates)})."
        )
        print("This is a fallback evaluation split, not a replacement for the intended 2024/2025 test set.")

        holdout_mask = df_master["Date"].isin(holdout_dates)
        df_test = df_master[holdout_mask].copy()
        df_train = df_master[~holdout_mask].copy()
        split_label = "fallback temporal date holdout"

    if df_train.empty or df_test.empty:
        raise RuntimeError(
            f"Invalid train/test split: train rows={len(df_train):,}, test rows={len(df_test):,}. "
            "Check MODE CSV availability, cached master completeness, and daily chunks."
        )

    print(
        f"\nPixel Memory -> Train: {len(df_train):,} | Test/Eval: {len(df_test):,} "
        f"| split={split_label}"
    )
    print(
        f"Train dates: {df_train['Date'].nunique():,} | Test/Eval dates: {df_test['Date'].nunique():,} "
        f"| train binary event rate={df_train[TARGET_COLUMN].mean():.6f} "
        f"| test binary event rate={df_test[TARGET_COLUMN].mean():.6f} "
        f"| train frac mean={df_train[TRAIN_TARGET_COLUMN].mean():.6f} "
        f"| test frac mean={df_test[TRAIN_TARGET_COLUMN].mean():.6f}"
    )

    return df_train, df_test, split_label

