def _rap_expected_catalog_url(date_str, valid_offset_fhr):
    """
    Exact NCEI historical THREDDS catalog URL form supplied by Tyreek.
    """
    date_str = str(date_str)
    yyyymm = date_str[:6]
    actual_fhr = int(valid_offset_fhr) + RAP_FILE_FHR_OFFSET
    filename = f"rap_130_{date_str}_{RAP_INIT_CYCLE_HOUR:02d}00_{actual_fhr:03d}.grb2"
    return (
        f"https://www.ncei.noaa.gov/thredds/catalog/model-rap130-old/"
        f"{yyyymm}/{date_str}/catalog.html?dataset=rap130-old/{yyyymm}/{date_str}/{filename}"
    )


def _rap_expected_aws_url(date_str, valid_offset_fhr):
    """
    AWS RAP object URL for newer public-cloud archive dates.
    """
    date_str = str(date_str)
    actual_fhr = int(valid_offset_fhr) + RAP_FILE_FHR_OFFSET
    return (
        f"https://noaa-rap-pds.s3.amazonaws.com/rap.{date_str}/"
        f"rap.t{RAP_INIT_CYCLE_HOUR:02d}z.awp130pgrbf{actual_fhr:02d}.grib2"
    )


def _rap_source_probe_ok(date_str, valid_offset_fhr):
    """
    Fast source-coverage check for one date/hour.

    First trust the local RAP cache if an equivalent validated file is already present.
    Historical 2019 then checks exact catalog URL; newer AWS dates check AWS object HEAD.
    """
    prior_ok, prior_path = prior_rap_feature_chunk_exists(date_str)
    if prior_ok:
        # v26 can rebuild the MRMS/FFG target from a prior RAP-feature chunk, so RAP
        # remote availability is irrelevant for this date.
        return True, "prior-feature-chunk", prior_path

    cached = find_existing_valid_rap_cache(date_str, valid_offset_fhr, output_dir=RAP_DIR, verbose=False)
    if cached:
        return True, "local-cache", cached

    date_i = int(str(date_str))

    try:
        if RAP_THREDDS_OLD_START <= date_i <= RAP_THREDDS_OLD_END:
            url = _rap_expected_catalog_url(date_str, valid_offset_fhr)
            resp = safe_requests_get(url, timeout=RAP_PREFLIGHT_TIMEOUT, allow_redirects=True)
            return resp.status_code == 200, resp.status_code, url

        if date_i >= RAP_AWS_PUBLIC_ARCHIVE_START:
            url = _rap_expected_aws_url(date_str, valid_offset_fhr)
            resp = safe_requests_head(url, timeout=RAP_PREFLIGHT_TIMEOUT, allow_redirects=True)
            # Some object services behave oddly on HEAD; fall back to a byte-range GET.
            if resp.status_code != 200:
                resp = safe_requests_get(
                    url,
                    timeout=RAP_PREFLIGHT_TIMEOUT,
                    headers={"Range": "bytes=0-0"},
                    allow_redirects=True,
                    stream=True,
                )
            return resp.status_code in (200, 206), resp.status_code, url

        return False, None, None

    except Exception as e:
        return False, repr(e), url if "url" in locals() else None


def preflight_filter_rap_source_coverage(all_dates):
    """
    Remove dates that do not have every required RAP 09z forecast file available
    before launching Ray extraction.

    This avoids 20+ minutes of workers failing on catalog 404s.
    """
    if not RAP_PREFLIGHT_SOURCE_COVERAGE:
        return list(all_dates)

    rows = []
    kept = []

    print("\nPreflighting RAP source coverage before extraction...")

    for d in tqdm(list(all_dates), desc="RAP source preflight", unit="date"):
        missing = []
        statuses = {}

        for fhr in MIN_REQUIRED_FORECAST_HOURS:
            ok, status, url = _rap_source_probe_ok(d, fhr)
            statuses[f"valid{int(fhr):02d}"] = status
            if not ok:
                missing.append(int(fhr))

        complete = len(missing) == 0
        if complete:
            kept.append(str(d))

        rows.append({
            "date": str(d),
            "complete": complete,
            "missing_valid_offsets": ",".join(f"{h:02d}" for h in missing),
            **statuses,
        })

    try:
        os.makedirs(RAP_DOWNLOAD_DEBUG_DIR, exist_ok=True)
        out = os.path.join(RAP_DOWNLOAD_DEBUG_DIR, "rap_source_preflight_coverage.csv")
        pd.DataFrame(rows).to_csv(out, index=False)
        print(f"RAP preflight coverage summary: {out}")
    except Exception:
        pass

    skipped = len(all_dates) - len(kept)
    print(f"RAP source preflight kept {len(kept):,} / {len(all_dates):,} dates; skipped {skipped:,}.")

    if skipped:
        first_bad = [r for r in rows if not r["complete"]][:10]
        print("First incomplete RAP dates after preflight:")
        for r in first_bad:
            print(f"  {r['date']}: missing [{r['missing_valid_offsets']}]")

    return kept


def filter_dates_for_rap_direct_availability(all_dates):
    """
    Keep MODE dates covered by direct RAP forecast-file sources.

    Coverage rules:
      - 2019-01-01 through 2019-12-31: NCEI historical THREDDS rap130-old
      - date >= RAP_AWS_PUBLIC_ARCHIVE_START: AWS/mirrors/recent NCEI
      - otherwise: skip
    """
    kept = []
    skipped = []

    for d in all_dates:
        try:
            di = int(d)
            old_ok = int(RAP_THREDDS_OLD_START) <= di <= int(RAP_THREDDS_OLD_END)
            aws_ok = di >= int(RAP_AWS_PUBLIC_ARCHIVE_START)
            if old_ok or aws_ok:
                kept.append(str(d))
            else:
                skipped.append(str(d))
        except Exception:
            skipped.append(str(d))

    if skipped:
        print(
            f"Skipping {len(skipped):,} MODE dates outside direct RAP forecast availability "
            f"(keeping {RAP_THREDDS_OLD_START}-{RAP_THREDDS_OLD_END} and >= {RAP_AWS_PUBLIC_ARCHIVE_START})."
        )
        print(f"  first skipped: {skipped[:5]}")
        print(f"  last skipped:  {skipped[-5:]}")

    print(
        f"MODE dates after RAP source filter: {len(kept):,} / {len(all_dates):,} "
        f"(2019 THREDDS + AWS >= {RAP_AWS_PUBLIC_ARCHIVE_START})"
    )
    return kept, skipped


